// Unit 26: Medienkritik
// Level: B2

const UNIT_26 =
{n:26,lang:"de",srcLang:"en",track:"v2",title:"Medienkritik",sub:"Zwischen den Zeilen",icon:"📰",level:"B2.1",color:"#7B5EE8",lessons:[
{id:"deu_r26l1",title:"Die Morgenzeitung",icon:"📰",xp:15,board:true,steps:[
{type:"intro",title:"Die Morgenzeitung",desc:"Enter the world of German media. Verumius sits in his kitchen, reads Die Zeit, and marks unknown words with a red pen. Deutschlandfunk plays on the radio.",goals:["Learn core journalism vocabulary","Understand the German media landscape","Recognize journalistic writing patterns","Follow Verumius in his new morning ritual"]},
{type:"story",speaker:"narrator",mood:"intimate",art:"de-ber-kitchen-morning",trg:"Verumius' Küche. Halb sieben morgens. Die Zeit liegt aufgeschlagen auf dem Tisch. Ein roter Stift neben einer Kaffeetasse. Das Radio murmelt Deutschlandfunk. Das ist Verumius' neues Morgenritual: deutsche Medien, total.",src:"Verumius's kitchen. Six thirty in the morning. Die Zeit lies open on the table. A red pen next to a coffee cup. The radio murmurs Deutschlandfunk. This is Verumius's new morning ritual: German media immersion."},
{type:"story",speaker:"narrator",mood:"reflective",trg:"Er liest. Er unterstreicht. Jedes dritte Wort bekommt einen roten Strich. Die Schlagzeilen sind raetselhaft: 'Der veröffentlichte Bericht sorgt für Aufregung.' Was bedeutet 'veröffentlichte' vor einem Nomen?",src:"He reads. He underlines. Every third word gets a red mark. The headlines are cryptic: 'The published report causes a stir.' What does 'published' mean in front of a noun like that?"},
{type:"story",speaker:"verumius",mood:"thinking",trg:"Die Schlagzeilen verstehe ich. Aber diese langen Ausdrücke vor dem Nomen? 'Die von der Regierung geplante Maßnahme.' Das ist wie ein ganzer Satz vor dem Wort.",src:"I understand the headlines. But these long expressions before the noun? 'The measure planned by the government.' That is like a whole sentence before the word."},
{type:"story",speaker:"narrator",mood:"warm",trg:"Das Radio wechselt zu einem Kommentar. Die Journalistin sagt: 'Das lässt sich nicht einfach erklären.' Noch eine neue Struktur: lassen + sich. Verumius schreibt sie auf.",src:"The radio switches to a commentary. The journalist says: 'That cannot be explained so easily.' Another new structure: lassen + sich. Verumius writes it down."},
{type:"teach",trg:"der Journalismus",src:"journalism",pos:"noun",gender:"m",note:"Masculine noun. From French 'journalisme.'\n'Qualitaetsjournalismus' (quality journalism).",example:"A: Was studierst du?\nB: Journalismus. Ich will Journalist werden.\nA: Journalismus ist wichtig für die Demokratie.\nB: Ja, ohne Journalismus keine informierten Bürger.",exampleSrc:"A: What are you studying?\nB: Journalism. I want to become a journalist.\nA: Journalism is important for democracy.\nB: Yes, without journalism no informed citizens.",funFact:"From French 'journalisme.' Germany has a strong tradition of Qualitaetsjournalismus. The Grundgesetz (constitution) guarantees Pressefreiheit. Journalism is a protected right in Germany."},
{type:"teach",trg:"der Journalist",src:"journalist (male)",pos:"noun",gender:"m",note:"Masculine noun. N-Deklination: Journalist, Journalisten.\nFrom French 'journaliste.'",example:"A: Wer hat den Artikel geschrieben?\nB: Ein Journalist der Sueddeutschen Zeitung.\nA: Ist er ein guter Journalist?\nB: Ja, er recherchiert immer gründlich.",exampleSrc:"A: Who wrote the article?\nB: A journalist from the Sueddeutsche Zeitung.\nA: Is he a good journalist?\nB: Yes, he always researches thoroughly.",funFact:"N-Deklination: den Journalisten, dem Journalisten. German journalists typically study at a Journalistenschule or complete a Volontariat (journalism apprenticeship). A two-year training that is uniquely German."},
{type:"teach",trg:"die Journalistin",src:"journalist (female)",pos:"noun",gender:"f",note:"Feminine noun. Journalist + '-in.'\nPlural: die Journalistinnen.",example:"A: Kennst du die Journalistin im Fernsehen?\nB: Ja, sie ist sehr bekannt.\nA: Sie berichtet immer aus dem Ausland.\nB: Eine mutige Journalistin.",exampleSrc:"A: Do you know the journalist on TV?\nB: Yes, she is very well known.\nA: She always reports from abroad.\nB: A brave journalist.",funFact:"The -in pattern holds perfectly across professions: Journalist/Journalistin, Redakteur/Redakteurin. Women now make up about 40% of German newsrooms. The feminine form is always used when referring to a specific woman."},
{type:"mc",q:"In deutschen Medien arbeiten Journalisten und Journalistinnen. Wie bildet man die weibliche Form?",opts:["Journalist wird zu Journalistin mit der Endung -in","Journalist wird zu Journalistfrau","Journalist bleibt gleich für beide Geschlechter","Journalist wird zu Journalisterin mit -erin"],ans:"Journalist wird zu Journalistin mit der Endung -in",hint:"The standard German pattern for feminine professional titles. Add a specific suffix to the masculine form."},
{type:"teach",trg:"die Nachrichten",src:"the news",pos:"noun",gender:"pl",note:"Always plural when meaning 'news.'\n'Nachrichten hören' (to listen to the news).",example:"A: Hast du die Nachrichten gesehen?\nB: Ja, heute waren sie sehr interessant.\nA: Was war die wichtigste Nachricht?\nB: Ein neues Gesetz wurde beschlossen.",exampleSrc:"A: Did you watch the news?\nB: Yes, today they were very interesting.\nA: What was the most important news item?\nB: A new law was passed.",funFact:"'Nach' (after) + 'richten' (to direct). News: things directed after you so you know what happened. Die Tagesschau is Germany's most-watched Nachrichtensendung, broadcasting since 1952."},
{type:"teach",trg:"die Tageszeitung",src:"daily newspaper",pos:"noun",gender:"f",note:"Feminine noun. Tag (day) + Zeitung (newspaper).\nAbbreviated 'taz' for the Berlin paper.",example:"A: Liest du eine Tageszeitung?\nB: Ja, ich lese die Sueddeutsche Zeitung.\nA: Jeden Tag?\nB: Fast jeden Tag. Eine gute Tageszeitung braucht Zeit.",exampleSrc:"A: Do you read a daily newspaper?\nB: Yes, I read the Sueddeutsche Zeitung.\nA: Every day?\nB: Almost every day. A good daily newspaper takes time.",funFact:"Germany has many: Sueddeutsche Zeitung, Frankfurter Allgemeine Zeitung (FAZ), Die Welt. Also the name of a left-leaning Berlin paper: 'die tageszeitung' (lowercase, abbreviated 'taz'). Die Zeit is actually a Wochenzeitung (weekly)."},
{type:"teach",trg:"die Schlagzeile",src:"headline",pos:"noun",gender:"f",note:"Feminine noun. Schlag (hit) + Zeile (line).\n'Schlagzeilen machen' (to make headlines).",example:"A: Hast du die Schlagzeile gelesen?\nB: Ja, sie ist sehr dramatisch.\nA: Manche Schlagzeilen übertreiben.\nB: Stimmt. Man muss den ganzen Artikel lesen.",exampleSrc:"A: Did you read the headline?\nB: Yes, it is very dramatic.\nA: Some headlines exaggerate.\nB: True. You have to read the whole article.",funFact:"A 'strike line' that hits you in the face with information. 'Schlagzeilen machen' means causing a sensation. German tabloid Schlagzeilen are famously bold and loud. Quality papers keep theirs more restrained."},
{type:"fb",s:"Die {1} auf Seite eins war sehr dramatisch und übertrieben.",a:["Schlagzeile"],opts:["Tageszeitung","Schlagzeile","Sendung","Nachricht"],hint:"The feminine noun for a newspaper headline. Schlag (hit) + Zeile (line). A line that hits you.",sSrc:"The headline on page one was very dramatic and exaggerated."},
{type:"teach",trg:"der Kommentar",src:"commentary, opinion piece",pos:"noun",gender:"m",note:"Masculine noun. From Latin 'commentarius.'\nSeparate from Bericht (report).",example:"A: Ist das ein Bericht oder ein Kommentar?\nB: Ein Kommentar. Der Autor gibt seine Meinung.\nA: In deutschen Zeitungen steht das klar dabei.\nB: Ja, Bericht und Kommentar werden getrennt.",exampleSrc:"A: Is that a report or a commentary?\nB: A commentary. The author gives his opinion.\nA: In German newspapers that is clearly marked.\nB: Yes, report and commentary are kept separate.",funFact:"German newspapers clearly label Kommentare. They are separate from Berichte (reports). Opinion vs. fact. The distinction matters deeply in German journalism ethics. Mixing them is considered unprofessional."},
{type:"teach",trg:"die Sendung",src:"broadcast, program",pos:"noun",gender:"f",note:"Feminine noun. From 'senden' (to send/broadcast).\n'Nachrichtensendung' (news broadcast).",example:"A: Welche Sendung schaust du gern?\nB: Ich mag die Sendung mit der Maus.\nA: Das ist eine Kindersendung!\nB: Ja, aber sie erklärt Dinge wunderbar.",exampleSrc:"A: Which program do you like to watch?\nB: I like Die Sendung mit der Maus.\nA: That is a children's program!\nB: Yes, but it explains things wonderfully.",funFact:"'Die Sendung mit der Maus' is Germany's most beloved children's show, running since 1971. 'Nachrichtensendung' = news broadcast. One root word, 'senden,' builds an entire media vocabulary."},
{type:"teach",trg:"der Rundfunk",src:"broadcasting",pos:"noun",gender:"m",note:"Masculine noun. Rund (around) + Funk (radio).\n'Öffentlich-rechtlicher Rundfunk' (public broadcasting).",example:"A: Was ist der Rundfunk?\nB: Radio und Fernsehen zusammen.\nA: Und der öffentlich-rechtliche Rundfunk?\nB: Das sind ARD, ZDF und Deutschlandfunk.",exampleSrc:"A: What is Rundfunk?\nB: Radio and television together.\nA: And public broadcasting?\nB: Those are ARD, ZDF, and Deutschlandfunk.",funFact:"Radio signals sent 'around' to everyone. 'Öffentlich-rechtlicher Rundfunk' (public broadcasting) is funded by the Rundfunkbeitrag. Every German household pays about 18 euros per month for it. A unique funding model."},
{type:"teach",trg:"die Massenmedien",src:"mass media",pos:"noun",gender:"pl",note:"Always plural. Massen (mass) + Medien (media).\n'Die Macht der Massenmedien' (the power of mass media).",example:"A: Welche Massenmedien nutzt du?\nB: Zeitungen, Radio und Internet.\nA: Die Massenmedien haben grossen Einfluss.\nB: Deshalb ist Medienkompetenz so wichtig.",exampleSrc:"A: Which mass media do you use?\nB: Newspapers, radio, and internet.\nA: Mass media have great influence.\nB: That is why media literacy is so important.",funFact:"Print, radio, television, internet. 'Die Macht der Massenmedien' (the power of mass media) is a classic German essay topic. The singular 'das Medium' is rarely used for traditional media; it is almost always 'die Medien.'"},
{type:"mc",q:"ARD, ZDF und Deutschlandfunk sind öffentlich-rechtlicher Rundfunk. Wie wird er finanziert?",opts:["Durch Werbung und private Sponsoren","Durch die Regierung ganz direkt","Durch den Rundfunkbeitrag der Bürger","Durch Abonnements und freiwillige Spenden"],ans:"Durch den Rundfunkbeitrag der Bürger",hint:"Germany's public broadcasting model is unique: funded by citizens through a mandatory monthly contribution, not by the state or advertisers."}
]},
{id:"deu_r26l1b",title:"Die Morgenzeitung (Teil 2)",icon:"📰",xp:15,board:true,steps:[
{type:"intro",title:"Die Morgenzeitung (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"berichten",src:"to report",pos:"verb",gender:null,note:"Regular verb. 'Über etwas berichten' (to report on something).\nThe core journalistic verb.",example:"A: Worüber berichten Sie?\nB: Ich berichte über die Wahl.\nA: Berichten Sie live?\nB: Ja, wir berichten live aus dem Bundestag.",exampleSrc:"A: What are you reporting on?\nB: I am reporting on the election.\nA: Are you reporting live?\nB: Yes, we are reporting live from the Bundestag.",funFact:"The core journalistic verb. 'Wir berichten live' (We are reporting live). Neutral, factual, objective. Der Bericht (the report) is the noun. A journalist who berichtet states facts without personal opinion."},
{type:"teach",trg:"informieren",src:"to inform",pos:"verb",gender:null,note:"Regular verb. From Latin 'informare.'\nReflexive: 'sich informieren' (to inform oneself).",example:"A: Wie informierst du dich über Politik?\nB: Ich lese Zeitungen und hoere Radio.\nA: Man muss sich gut informieren.\nB: Ja, informierte Bürger sind wichtig.",exampleSrc:"A: How do you inform yourself about politics?\nB: I read newspapers and listen to the radio.\nA: One has to inform oneself well.\nB: Yes, informed citizens are important.",funFact:"From Latin 'informare' (to give form to). Also reflexive: 'sich informieren' (to inform oneself). The media's primary duty is to inform. 'Gut informiert' (well informed) is the goal of every news consumer."},
{type:"teach",trg:"recherchieren",src:"to investigate, to research",pos:"verb",gender:null,note:"Regular verb. From French 'rechercher.'\n'Gruendlich recherchieren' (to research thoroughly).",example:"A: Wie lange haben Sie recherchiert?\nB: Drei Monate. Gruendlich recherchieren braucht Zeit.\nA: Und was haben Sie herausgefunden?\nB: Die Wahrheit. Aber die war nicht leicht zu finden.",exampleSrc:"A: How long did you investigate?\nB: Three months. Thorough research takes time.\nA: And what did you find out?\nB: The truth. But it was not easy to find.",funFact:"From French 'rechercher' (to search again). The essential journalistic skill. A journalist who does not recherchieren is not a journalist. 'Investigative Recherche' is the German term for in-depth investigative reporting."},
{type:"teach",trg:"kommentieren",src:"to comment on",pos:"verb",gender:null,note:"Regular verb. From Kommentar.\n'Ein Ereignis kommentieren' (to comment on an event).",example:"A: Darf ein Journalist kommentieren?\nB: Ja, aber nur im Kommentar, nicht im Bericht.\nA: Wie kommentieren Sie dieses Ereignis?\nB: Ich finde es besorgniserregend.",exampleSrc:"A: Is a journalist allowed to comment?\nB: Yes, but only in the commentary, not in the report.\nA: How do you comment on this event?\nB: I find it concerning.",funFact:"Separating Bericht from Kommentar is journalism ethics. The noun Kommentar becomes the verb kommentieren. In German media, the line between reporting and commenting is a professional boundary."},
{type:"teach",trg:"serioes",src:"serious, reputable",pos:"adj",gender:null,note:"Adjective. From French 'serieux.'\n'Eine serioese Zeitung' (a reputable newspaper).",example:"A: Ist diese Zeitung serioes?\nB: Ja, die FAZ ist sehr serioes.\nA: Und die Bild-Zeitung?\nB: Die ist eher boulevardesk als serioes.",exampleSrc:"A: Is this newspaper reputable?\nB: Yes, the FAZ is very reputable.\nA: And the Bild newspaper?\nB: That is more tabloid than reputable.",funFact:"'Serioeser Journalismus' (serious journalism) vs. Boulevardpresse (tabloid press). The dividing line of German media. A serioese Quelle (reputable source) is the foundation of trust in reporting."},
{type:"teach",trg:"glaubwürdig",src:"credible, trustworthy",pos:"adj",gender:null,note:"Adjective. Glaub (believe) + würdig (worthy).\n'Glaubwürdige Quellen' (credible sources).",example:"A: Ist diese Quelle glaubwürdig?\nB: Ja, der Autor ist sehr glaubwürdig.\nA: Woran erkennt man glaubwürdige Quellen?\nB: An der Transparenz und den Fakten.",exampleSrc:"A: Is this source credible?\nB: Yes, the author is very credible.\nA: How do you recognize credible sources?\nB: By the transparency and the facts.",funFact:"A journalist's most valuable asset. 'Die Glaubwürdigkeit' (credibility) is the nominalized form. Once you lose your Glaubwürdigkeit, you cannot get it back. The compound literally means 'worthy of being believed.'"},
{type:"teach",trg:"unabhängig",src:"independent",pos:"adj",gender:null,note:"Adjective. Un- (not) + abhängig (dependent).\n'Unabhängige Medien' (independent media).",example:"A: Sind deutsche Medien unabhängig?\nB: Ja, die Presse ist unabhängig vom Staat.\nA: Das ist wichtig für die Demokratie.\nB: Unabhängigkeit ist die Grundlage guter Medien.",exampleSrc:"A: Are German media independent?\nB: Yes, the press is independent from the state.\nA: That is important for democracy.\nB: Independence is the foundation of good media.",funFact:"The press must be unabhängig from government and business. Article 5 of the Grundgesetz protects this independence. 'Unabhängigkeit' is the noun. In Germany, public broadcasting is designed to be structurally unabhängig."},
{type:"teach",trg:"angeblich",src:"allegedly",pos:"adv",gender:null,note:"Adverb. An + geblich (from geben).\nRed flag word in journalism.",example:"A: Der angebliche Experte hat keine Qualifikation.\nB: Angeblich? Dann ist es nicht bewiesen?\nA: Nein, angeblich heißt: es wird behauptet.\nB: Dann muss man weiter recherchieren.",exampleSrc:"A: The alleged expert has no qualification.\nB: Allegedly? Then it is not proven?\nA: No, allegedly means: it is claimed.\nB: Then one must research further.",funFact:"A word journalists use when they cannot confirm something. Red flag word: if something is 'angeblich,' doubt it. 'Der angebliche Experte' (the alleged expert) signals that the claim has not been verified."},
{type:"teach",trg:"offenbar",src:"apparently, evidently",pos:"adv",gender:null,note:"Adverb. Offen (open) + -bar (capable of).\nStronger than 'anscheinend.'",example:"A: Offenbar hat die Regierung das gewusst.\nB: Offenbar? Das klingt ziemlich sicher.\nA: Ja, offenbar ist stärker als anscheinend.\nB: Aber schwaecher als offensichtlich.",exampleSrc:"A: Apparently the government knew about it.\nB: Apparently? That sounds fairly certain.\nA: Yes, offenbar is stronger than anscheinend.\nB: But weaker than offensichtlich.",funFact:"Something that is 'open-able' to see. The scale of certainty in German: anscheinend (seemingly) < offenbar (apparently) < offensichtlich (obviously). Journalists choose carefully between these three."},
{type:"fb",s:"{1} hat die Regierung das gewusst. Das klingt ziemlich sicher.",a:["Offenbar"],opts:["Angeblich","Bekanntlich","Serioes","Offenbar"],hint:"The adverb that means 'apparently' but with more certainty than 'anscheinend.' Offen + -bar.",sSrc:"Apparently the government knew about it. That sounds fairly certain."},
{type:"teach",trg:"bekanntlich",src:"as is well known",pos:"adv",gender:null,note:"Adverb. Bekannt (known) + -lich.\nAcademic and journalistic register.",example:"A: Bekanntlich ist Pressefreiheit ein Grundrecht.\nB: Ja, das weiß jeder.\nA: Bekanntlich klingt sehr formell.\nB: Es passt in Zeitungsartikel und Essays.",exampleSrc:"A: As is well known, press freedom is a fundamental right.\nB: Yes, everyone knows that.\nA: Bekanntlich sounds very formal.\nB: It fits in newspaper articles and essays.",funFact:"Signals shared knowledge. Academic and journalistic. 'Bekanntlich ist Deutschland ein foederaler Staat' (As is well known, Germany is a federal state). Using bekanntlich assumes your audience already knows the fact. It adds authority."},
{type:"mc",q:"Verumius liest Die Zeit. Was ist Die Zeit?",opts:["Eine deutsche Wochenzeitung","Ein deutsches Nachrichtenradio","Eine Nachrichtenfernsehsendung","Ein politisches Onlineforum"],ans:"Eine deutsche Wochenzeitung",hint:"Die Zeit is one of Germany's most respected print publications. Think about how its name relates to its publication schedule and what compound noun that forms."},
{type:"match",pairs:[{trg:"Tageszeitung",src:"daily newspaper"},{trg:"Rundfunk",src:"broadcasting"},{trg:"Schlagzeile",src:"headline"},{trg:"Kommentar",src:"opinion piece"}]},
{type:"story",speaker:"verumius",mood:"determined",art:"de-ber-kitchen-morning",trg:"Er faltet die Zeitung zusammen. Sechzehn rote Markierungen auf einer Seite. Morgen werden es weniger sein. Er nimmt den letzten Schluck Kaffee und schaltet das Radio aus.",src:"He folds the newspaper. Sixteen red marks on one page. Tomorrow there will be fewer. He takes the last sip of coffee and turns off the radio."},
{type:"mc",q:"Was bedeutet 'informieren'?",opts:["as is well known","to inform","journalism","daily newspaper"],ans:"to inform",hint:"Near-identical in English. Latin: informare (to give form to knowledge)."},
{type:"fb",s:"Darf ein Journalist {1}?",a:["kommentieren"],opts:["kommentieren","informieren","die Journalistin","der Journalist"],hint:"Cognate of English 'comment.' To share an opinion on a news story.",sSrc:"Is a journalist allowed to comment?"}
]},
{id:"deu_r26l2",title:"Wem kann man glauben?",icon:"🔍",xp:15,board:true,steps:[
{type:"intro",title:"Wem kann man glauben?",desc:"Media criticism needs vocabulary. Learn words for disinformation, manipulation, and media literacy. Understand how to evaluate sources critically.",goals:["Learn media criticism vocabulary","Recognize disinformation strategies","Understand German press freedom","Evaluate media sources critically"]},
{type:"story",speaker:"narrator",mood:"wry",art:"de-ber-kitchen-table",trg:"Frühstück. Verumius hat drei Zeitungen aufgeschlagen. Die Zeit, die FAZ, die taz. Drei Artikel über dasselbe Thema. Drei voellig verschiedene Geschichten.",src:"Breakfast. Verumius has three newspapers open. Die Zeit, the FAZ, the taz. Three articles about the same topic. Three completely different stories."},
{type:"story",speaker:"verumius",mood:"puzzled",art:"de-ber-kitchen-table",trg:"Der eine sagt Fortschritt. Der andere sagt Skandal. Der dritte sagt: alles komplizierter als gedacht. Wem soll man glauben, wenn alle 'Fakten' haben?",src:"One says progress. Another says scandal. The third says: everything more complicated than expected. Whom should you believe when they all have 'facts'?"},
{type:"story",speaker:"narrator",mood:"reflective",art:"de-ber-kitchen-table",trg:"Er markiert die Quellen mit verschiedenen Farben. Rot für unbelegte Behauptungen. Gruen für nachprüfbare Fakten. Die meisten Markierungen sind rot.",src:"He marks the sources with different colors. Red for unsubstantiated claims. Green for verifiable facts. Most marks are red."},
{type:"teach",trg:"die Pressefreiheit",src:"press freedom",pos:"noun",gender:"f",note:"Feminine noun. Presse + Freiheit (freedom).\nArticle 5 of the Grundgesetz.",example:"A: Gibt es Pressefreiheit in Deutschland?\nB: Ja, Artikel 5 garantiert die Pressefreiheit.\nA: Ist das überall so?\nB: Nein, viele Laender haben keine Pressefreiheit.",exampleSrc:"A: Is there press freedom in Germany?\nB: Yes, Article 5 guarantees press freedom.\nA: Is it like that everywhere?\nB: No, many countries do not have press freedom.",funFact:"Article 5 of the German Grundgesetz: 'Die Pressefreiheit und die Freiheit der Berichterstattung werden gewährleistet.' A non-negotiable right. Germany ranks consistently in the top 20 of press freedom indices."},
{type:"teach",trg:"die Meinungsfreiheit",src:"freedom of expression",pos:"noun",gender:"f",note:"Feminine noun. Meinung (opinion) + Freiheit.\nAlso Article 5, but with limits.",example:"A: Darf man in Deutschland alles sagen?\nB: Meinungsfreiheit hat Grenzen.\nA: Welche Grenzen?\nB: Volksverhetzung und Holocaustleugnung sind verboten.",exampleSrc:"A: Can you say anything in Germany?\nB: Freedom of expression has limits.\nA: Which limits?\nB: Incitement and Holocaust denial are forbidden.",funFact:"Also Article 5 of the Grundgesetz. But Meinungsfreiheit has limits in Germany. Volksverhetzung (incitement) and Holocaustleugnung (Holocaust denial) are criminal offenses. Freedom with responsibility."},
{type:"teach",trg:"die Desinformation",src:"disinformation",pos:"noun",gender:"f",note:"Feminine noun. Des- (un/dis) + Information.\nDeliberately false information.",example:"A: Was ist Desinformation?\nB: Absichtlich falsche Informationen.\nA: Ist das dasselbe wie Fehlinformation?\nB: Nein, Fehlinformation ist unabsichtlich falsch.",exampleSrc:"A: What is disinformation?\nB: Deliberately false information.\nA: Is that the same as misinformation?\nB: No, misinformation is unintentionally wrong.",funFact:"Different from Fehlinformation (misinformation, unintentionally wrong). Desinformation is a weapon. The 'Des-' prefix signals deliberate undoing of truth. Intentional deception designed to manipulate."},
{type:"teach",trg:"die Fake News",src:"fake news",pos:"noun",gender:"pl",note:"Always plural in German. Borrowed from English.\n'Fake News erkennen' (to recognize fake news).",example:"A: Wie erkennt man Fake News?\nB: Man prüft die Quellen.\nA: Fake News verbreiten sich schnell.\nB: Ja, besonders in sozialen Medien.",exampleSrc:"A: How do you recognize fake news?\nB: You check the sources.\nA: Fake news spread quickly.\nB: Yes, especially on social media.",funFact:"Borrowed from English. Always plural in German: 'die Fake News.' German also uses 'Falschmeldung' (false report) and 'Falschnachricht.' The English term became universal after 2016. 'Fake News erkennen' is now taught in German schools."},
{type:"mc",q:"Was ist der Unterschied zwischen Desinformation und Fehlinformation?",opts:["Desinformation ist absichtlich falsch, Fehlinformation unabsichtlich","Fehlinformation ist absichtlich falsch, Desinformation nicht","Es gibt keinen Unterschied zwischen beiden","Fehlinformation kommt aus dem Internet, Desinformation aus Zeitungen"],ans:"Desinformation ist absichtlich falsch, Fehlinformation unabsichtlich",hint:"The 'Des-' prefix signals deliberate undoing. One type of false information is intentional, the other is not."},
{type:"teach",trg:"die Propaganda",src:"propaganda",pos:"noun",gender:"f",note:"Feminine noun. From Latin 'propagare' (to spread).\nEspecially loaded word in Germany.",example:"A: Was ist der Unterschied zwischen Werbung und Propaganda?\nB: Propaganda will politisch beeinflussen.\nA: Das Wort hat eine dunkle Geschichte.\nB: Ja, besonders in Deutschland.",exampleSrc:"A: What is the difference between advertising and propaganda?\nB: Propaganda wants to influence politically.\nA: The word has a dark history.\nB: Yes, especially in Germany.",funFact:"Germany's history makes this word especially loaded. The Propagandaministerium under the Nazi regime weaponized media. Modern usage: systematic spreading of biased information to serve a political agenda."},
{type:"teach",trg:"die Manipulation",src:"manipulation",pos:"noun",gender:"f",note:"Feminine noun. From Latin 'manipulus' (handful).\n'Mediale Manipulation' (media manipulation).",example:"A: Gibt es Manipulation in den Medien?\nB: Ja, mediale Manipulation ist real.\nA: Wie schützt man sich?\nB: Durch kritisches Denken und Medienkompetenz.",exampleSrc:"A: Is there manipulation in the media?\nB: Yes, media manipulation is real.\nA: How do you protect yourself?\nB: Through critical thinking and media literacy.",funFact:"From Latin 'manipulus' (handful). Controlling what people think by controlling what they see. Subtler than Propaganda but equally dangerous. 'Mediale Manipulation' operates through selection, framing, and omission."},
{type:"teach",trg:"die Filterblase",src:"filter bubble",pos:"noun",gender:"f",note:"Feminine noun. Filter + Blase (bubble).\n'Aus der Filterblase ausbrechen' (to break out).",example:"A: Was ist eine Filterblase?\nB: Du siehst nur, was du schon glaubst.\nA: Wie bricht man aus der Filterblase aus?\nB: Man liest verschiedene Quellen.",exampleSrc:"A: What is a filter bubble?\nB: You only see what you already believe.\nA: How do you break out of the filter bubble?\nB: You read different sources.",funFact:"Algorithms show you what you already believe. You never see opposing views. 'Aus der Filterblase ausbrechen' (to break out of the filter bubble). A modern media challenge coined by Eli Pariser in 2011."},
{type:"teach",trg:"die Zensur",src:"censorship",pos:"noun",gender:"f",note:"Feminine noun. From Latin 'censura.'\nArticle 5: 'Eine Zensur findet nicht statt.'",example:"A: Gibt es Zensur in Deutschland?\nB: Nein, das Grundgesetz verbietet Zensur.\nA: War das immer so?\nB: Nein, in der DDR gab es strenge Zensur.",exampleSrc:"A: Is there censorship in Germany?\nB: No, the constitution prohibits censorship.\nA: Was it always like that?\nB: No, in the GDR there was strict censorship.",funFact:"Article 5 of the Grundgesetz states: 'Eine Zensur findet nicht statt' (There shall be no censorship). Historical context: GDR censorship was pervasive. The memory shapes German media law today."},
{type:"teach",trg:"die Berichterstattung",src:"reporting, media coverage",pos:"noun",gender:"f",note:"Feminine noun. Bericht + Erstattung (rendering).\n'Objektive Berichterstattung' (objective reporting).",example:"A: Wie war die Berichterstattung?\nB: Einseitig. Nur eine Perspektive.\nA: Gute Berichterstattung zeigt alle Seiten.\nB: Ja, objektive Berichterstattung ist das Ziel.",exampleSrc:"A: How was the reporting?\nB: One-sided. Only one perspective.\nA: Good reporting shows all sides.\nB: Yes, objective reporting is the goal.",funFact:"The compound captures the formal act of rendering reports to the public. 'Objektive Berichterstattung' is the journalistic ideal. 'Tendenzoese Berichterstattung' (biased reporting) is its opposite and a serious accusation."},
{type:"teach",trg:"die Medienkompetenz",src:"media literacy",pos:"noun",gender:"f",note:"Feminine noun. Medien + Kompetenz (competence).\nA core skill taught in German schools.",example:"A: Was ist Medienkompetenz?\nB: Die Faehigkeit, Medien kritisch zu bewerten.\nA: Lernt man das in der Schule?\nB: Ja, Medienkompetenz wird immer wichtiger.",exampleSrc:"A: What is media literacy?\nB: The ability to evaluate media critically.\nA: Do you learn that in school?\nB: Yes, media literacy is becoming ever more important.",funFact:"The ability to critically evaluate media. German schools increasingly teach Medienkompetenz as a core skill. Knowing HOW to read news, not just WHAT to read. In the age of Fake News, Medienkompetenz is survival."},
{type:"fb",s:"Algorithmen zeigen dir nur, was du schon glaubst. Das nennt man eine {1}.",a:["Filterblase"],opts:["Zensur","Filterblase","Propaganda","Pressefreiheit"],hint:"The compound noun for the bubble that filters what you see online. Filter + Blase.",sSrc:"Algorithms show you only what you already believe. That is called a filter bubble."}
]},
{id:"deu_r26l2b",title:"Wem kann man glauben? (Teil 2)",icon:"🔍",xp:15,board:true,steps:[
{type:"intro",title:"Wem kann man glauben? (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"manipulieren",src:"to manipulate",pos:"verb",gender:null,note:"Regular verb. From Manipulation.\n'Informationen manipulieren' (to manipulate information).",example:"A: Kann man Bilder manipulieren?\nB: Ja, digitale Bilder lassen sich leicht manipulieren.\nA: Das ist gefaehrlich.\nB: Deshalb muss man Quellen prüfen.",exampleSrc:"A: Can images be manipulated?\nB: Yes, digital images can be easily manipulated.\nA: That is dangerous.\nB: That is why you must check sources.",funFact:"Manipulation becomes manipulieren. Active deception. 'Manipulierte Bilder' (manipulated images) are a growing problem. The Partizip II 'manipuliert' is often used as an adjective: 'manipulierte Daten' (manipulated data)."},
{type:"teach",trg:"beeinflussen",src:"to influence",pos:"verb",gender:null,note:"Regular verb. Be- + Einfluss (influence).\nNot always negative.",example:"A: Wer beeinflusst die öffentliche Meinung?\nB: Die Medien beeinflussen sie stark.\nA: Ist das immer schlecht?\nB: Nein, gute Medien beeinflussen positiv.",exampleSrc:"A: Who influences public opinion?\nB: The media influence it strongly.\nA: Is that always bad?\nB: No, good media influence positively.",funFact:"Not always negative: teachers also beeinflussen. Context determines whether it is manipulation or education. 'Die öffentliche Meinung beeinflussen' (to influence public opinion) can be responsible journalism or propaganda."},
{type:"teach",trg:"verbreiten",src:"to spread, to disseminate",pos:"verb",gender:null,note:"Regular verb. Ver- + breit (broad).\n'Falschnachrichten verbreiten' (to spread false news).",example:"A: Wer verbreitet diese Nachricht?\nB: Sie verbreitet sich im Internet.\nA: Fake News verbreiten sich schnell.\nB: Schneller als die Wahrheit, leider.",exampleSrc:"A: Who is spreading this news?\nB: It is spreading on the internet.\nA: Fake news spread quickly.\nB: Faster than the truth, unfortunately.",funFact:"Making something broad, sending it everywhere. 'Die Verbreitung' (the spread) is the nominalized form. In the digital age, Falschnachrichten verbreiten sich schneller als Korrekturen (corrections)."},
{type:"teach",trg:"verfaelschen",src:"to falsify, to distort",pos:"verb",gender:null,note:"Regular verb. Ver- + faelschen (to falsify).\n'Daten verfaelschen' (to falsify data).",example:"A: Hat jemand die Daten verfaelscht?\nB: Ja, die Ergebnisse wurden verfaelscht.\nA: Das ist ein schweres Vergehen.\nB: Verfaelschte Daten zerstoeren Vertrauen.",exampleSrc:"A: Did someone falsify the data?\nB: Yes, the results were falsified.\nA: That is a serious offense.\nB: Falsified data destroy trust.",funFact:"The ver- prefix intensifies: faelschen is already bad, verfaelschen is deliberate and thorough corruption. 'Verfaelschte Ergebnisse' (falsified results) can destroy careers and institutions."},
{type:"teach",trg:"verschleiern",src:"to obscure, to cover up",pos:"verb",gender:null,note:"Regular verb. Ver- + Schleier (veil).\n'Die Wahrheit verschleiern' (to veil the truth).",example:"A: Warum verschleiert die Firma die Zahlen?\nB: Sie will die Wahrheit verbergen.\nA: Verschleiern ist subtiler als luegen.\nB: Ja, man macht die Wahrheit unsichtbar.",exampleSrc:"A: Why does the company obscure the numbers?\nB: It wants to hide the truth.\nA: Obscuring is subtler than lying.\nB: Yes, you make the truth invisible.",funFact:"Putting a Schleier (veil) over reality. Subtler than luegen (lying): making truth invisible without directly contradicting it. 'Verschleierungstaktik' (obfuscation tactic) is a compound that says it all."},
{type:"mc",q:"Die Firma will die Wahrheit verschleiern. Was bedeutet 'verschleiern'?",opts:["Die Wahrheit verbreiten und veröffentlichen","Die Wahrheit überprüfen und bestätigen","Die Wahrheit unsichtbar machen, verhüllen","Die Wahrheit unterstreichen und hervorheben"],ans:"Die Wahrheit unsichtbar machen, verhüllen",hint:"Ver- + Schleier (veil). Putting a veil over reality. Subtler than lying directly."},
{type:"teach",trg:"verzerren",src:"to distort",pos:"verb",gender:null,note:"Regular verb. Ver- + zerren (to pull/drag).\n'Die Realitaet verzerren' (to distort reality).",example:"A: Die Berichterstattung verzerrt die Realitaet.\nB: Ja, sie zeigt nur eine Seite.\nA: Verzerrte Medien sind gefaehrlich.\nB: Sie biegen die Fakten, ohne sie zu brechen.",exampleSrc:"A: The reporting distorts reality.\nB: Yes, it shows only one side.\nA: Distorted media are dangerous.\nB: They bend the facts without breaking them.",funFact:"Pulling reality out of shape. A Zerrung is a muscle strain. 'Verzerrte Berichterstattung' (distorted reporting) bends facts without breaking them. The image stays recognizable but is no longer accurate."},
{type:"teach",trg:"einseitig",src:"one-sided, biased",pos:"adj",gender:null,note:"Adjective. Ein (one) + seitig (sided).\nOpposite: 'ausgewogen' (balanced).",example:"A: Der Artikel ist einseitig.\nB: Er zeigt nur eine Perspektive.\nA: Guter Journalismus ist nie einseitig.\nB: Stimmt, beide Seiten müssen zu Wort kommen.",exampleSrc:"A: The article is one-sided.\nB: It shows only one perspective.\nA: Good journalism is never one-sided.\nB: True, both sides must have their say.",funFact:"Only showing one Seite (side) of the story. 'Einseitige Berichterstattung' (one-sided reporting) is a common criticism. The opposite: 'ausgewogen' (balanced). Every story has mindestens zwei Seiten (at least two sides)."},
{type:"teach",trg:"tendenzioes",src:"tendentious, biased",pos:"adj",gender:null,note:"Adjective. From Tendenz (tendency).\nStronger than einseitig: implies agenda.",example:"A: Ist dieser Bericht tendenzioes?\nB: Ja, er hat eine klare politische Tendenz.\nA: Tendenzioes ist stärker als einseitig.\nB: Ja, es bedeutet: absichtlich in eine Richtung.",exampleSrc:"A: Is this report tendentious?\nB: Yes, it has a clear political tendency.\nA: Tendentious is stronger than one-sided.\nB: Yes, it means: intentionally in one direction.",funFact:"Stronger than einseitig: tendenzioes implies a deliberate agenda. 'Tendenzioes berichten' (to report with bias). 'Die Tendenz' = the bias. A tendenzioeser Artikel tries to push the reader toward a predetermined conclusion."},
{type:"teach",trg:"parteiisch",src:"partisan, biased toward a party",pos:"adj",gender:null,note:"Adjective. Partei (party) + -isch.\nOpposite: 'unparteiisch' (impartial).",example:"A: Sind diese Medien parteiisch?\nB: Ja, sie unterstuetzen eine bestimmte Partei.\nA: Parteiische Medien sind problematisch.\nB: Unparteiische Berichterstattung ist das Ideal.",exampleSrc:"A: Are these media partisan?\nB: Yes, they support a specific party.\nA: Partisan media are problematic.\nB: Impartial reporting is the ideal.",funFact:"Taking a Partei (side/party). The opposite: 'unparteiisch' (impartial). In German media law, public broadcasters must be unparteiisch. Private media may be parteiisch, but they should disclose it."},
{type:"teach",trg:"voreingenommen",src:"prejudiced, biased",pos:"adj",gender:null,note:"Adjective. Vor (before) + eingenommen (taken in).\nThe strongest word for personal bias.",example:"A: Der Journalist ist voreingenommen.\nB: Er hatte seine Meinung schon vorher.\nA: Voreingenommene Journalisten sind ein Problem.\nB: Sie sehen nur, was sie sehen wollen.",exampleSrc:"A: The journalist is biased.\nB: He had his opinion already beforehand.\nA: Biased journalists are a problem.\nB: They only see what they want to see.",funFact:"Your opinion was 'taken in' before you even saw the evidence. The strongest word for personal bias. Stronger than einseitig or parteiisch because it describes an internal attitude, not just external behavior."},
{type:"tip",title:"Die ver-Vorsilbe in der Medienkritik",text:"German uses ver- to build words for distortion and deception:\n\nverfaelschen: to falsify (make false)\nverschleiern: to veil (cover truth)\nverzerren: to distort (pull out of shape)\nverbreiten: to spread (make broad)\nverleumden: to slander (attack reputation)\n\nThe ver- prefix often signals a change for the worse or the completion of an action. In media criticism, ver- words are red flags.",deepDive:{title:"Why ver-?",text:"The ver- prefix is one of German's most versatile. It can mean: completion (verbrennen: to burn up), change for worse (verfaelschen: to falsify), reversal (verlieren: to lose), or intensification (verschleiern: to obscure thoroughly). In media criticism, ver- words almost always signal something negative happening to truth or information."}},
{type:"mc",q:"Während serioese Medien gründlich recherchieren, verbreiten manche Seiten Desinformation. Was bedeutet Desinformation?",opts:["Absichtlich falsche Informationen","Ungenaue, aber dennoch ehrliche Berichte","Persönliche Meinungsäußerungen","Kommentare und Reaktionen zu Nachrichten"],ans:"Absichtlich falsche Informationen",hint:"The 'Des-' prefix signals the deliberate undoing of information. Intentionally false, not accidentally wrong."},
{type:"fb",s:"Ein Journalist, der nur eine Seite zeigt, berichtet {1}.",a:["einseitig"],opts:["serioes","einseitig","unabhängig","objektiv"],hint:"The adjective for reporting that presents only a single perspective. A compound of a number and a directional suffix.",sSrc:"A journalist who only shows one side reports one-sidedly."},
{type:"match",pairs:[{trg:"Filterblase",src:"filter bubble"},{trg:"Desinformation",src:"disinformation"},{trg:"Zensur",src:"censorship"},{trg:"Medienkompetenz",src:"media literacy"}]},
{type:"mc",q:"Während unabhängige Medien objektiv berichten, verzerren tendenziose Medien die Realitaet. Was signalisiert 'während' hier?",opts:["Eine zeitliche Gleichzeitigkeitsbeziehung (während/solange)","Eine Ursache-Wirkungs-Beziehung zwischen Ereignissen","Einen Kontrast zwischen zwei gegensaetzlichen Praktiken","Eine vollständige Übereinstimmung beider Seiten"],ans:"Einen Kontrast zwischen zwei gegensaetzlichen Praktiken",hint:"Während can mean 'while' in time or 'whereas' in contrast. Here it contrasts two types of media practice."},
{type:"mc",q:"Was bedeutet 'manipulieren'?",opts:["manipulation","to manipulate","press freedom","one-sided, biased"],ans:"to manipulate",hint:"Near-identical in English. Latin: manus (hand). To handle someone unfairly."},
{type:"fb",s:"Die Medien {1} sie stark.",a:["beeinflussen"],opts:["die Filterblase","die Desinformation","parteiisch","beeinflussen"],hint:"Be- + Einfluss (influence). Ein- (in) + Fluss (flow). Ideas flow in.",sSrc:"The media influence it strongly."},
{type:"mc",q:"Was bedeutet 'verfaelschen'?",opts:["press freedom","to falsify, to distort","fake news","media literacy"],ans:"to falsify, to distort",hint:"Ver- (wrongly) + falschen (to forge). To twist the truth deliberately."},
{type:"fb",s:"Ist dieser Bericht {1}?",a:["tendenzioes"],opts:["die Pressefreiheit","tendenzioes","verschleiern","verbreiten"],hint:"From Tendenz (tendency) + -ios. Leaning unfairly to one political side.",sSrc:"Is this report tendentious?"},
{type:"mc",q:"Was bedeutet 'voreingenommen'?",opts:["partisan, biased toward a party","media literacy","to influence","prejudiced, biased"],ans:"prejudiced, biased",hint:"Vor- (before) + eingenommen (taken in). Mind already made up in advance."}
]},
{id:"deu_r26l3",title:"Die Nachrichtenredaktion",icon:"🏢",xp:15,board:true,steps:[
{type:"intro",title:"Die Nachrichtenredaktion",desc:"A heated debate in the office kitchen about a newspaper article. Learn editorial vocabulary and master Partizipialattribute: entire subclauses packed as adjectives before the noun.",goals:["Learn vocabulary for editorial teams and roles","Master Partizipialattribute (participles before nouns)","Understand how German media is produced"]},
{type:"story",speaker:"narrator",mood:"tense",trg:"Bueroküche in der Mittagspause. Eine Zeitung liegt auf dem Tisch, aufgeschlagen bei einem kontroversen Artikel. Mia nimmt sie hoch. 'Habt ihr das gelesen?'",src:"Office kitchen at lunch. A newspaper lies on the table, open to a controversial article. Mia picks it up. 'Have you read this?'"},
{type:"story",speaker:"mia",mood:"passionate",trg:"Der veröffentlichte Bericht ist voellig einseitig! Die betroffenen Bürger kommen gar nicht zu Wort. Und die sogenannten Experten sind alle von der gleichen Partei.",src:"The published report is completely one-sided! The affected citizens do not get a word in. And the so-called experts are all from the same party."},
{type:"story",speaker:"narrator",mood:"observing",trg:"Ein Kollege widerspricht: 'Aber die recherchierten Fakten stimmen doch.' Mia schuettelt den Kopf: 'Fakten allein reichen nicht. Die Darstellung macht den Unterschied.'",src:"A colleague pushes back: 'But the researched facts are correct.' Mia shakes her head: 'Facts alone are not enough. The presentation makes the difference.'"},
{type:"story",speaker:"verumius",mood:"thinking",trg:"Der veröffentlichte Bericht... die betroffenen Bürger... Die stellen Partizipien einfach VOR das Nomen. Wie Adjektive. Aber sie tragen einen ganzen Nebensatz in sich.",src:"The published report... the affected citizens... They just place participles BEFORE the noun. Like adjectives. But they carry a whole subordinate clause within them."},
{type:"teach",trg:"die Redaktion",src:"editorial office, newsroom",pos:"noun",gender:"f",note:"Feminine noun. From Latin 'redactio.'\n'In der Redaktion' (in the newsroom).",example:"A: Wo arbeitest du?\nB: In der Redaktion der FAZ.\nA: Wie ist die Arbeit in der Redaktion?\nB: Hektisch, aber spannend.",exampleSrc:"A: Where do you work?\nB: In the editorial office of the FAZ.\nA: How is work in the newsroom?\nB: Hectic, but exciting.",funFact:"From Latin 'redactio' (bringing back into order). Where journalists work together to bring order to the day's news. 'Die Redaktion' means both the physical room and the team. 'Redaktionsschluss' (editorial deadline) waits for no one."},
{type:"teach",trg:"der Redakteur",src:"editor (male)",pos:"noun",gender:"m",note:"Masculine noun. From French 'redacteur.'\n'Chefredakteur' (editor-in-chief).",example:"A: Wer hat den Artikel bearbeitet?\nB: Der Redakteur der Kulturseite.\nA: Der Chefredakteur entscheidet am Ende.\nB: Ja, er hat das letzte Wort.",exampleSrc:"A: Who edited the article?\nB: The editor of the culture page.\nA: The editor-in-chief decides in the end.\nB: Yes, he has the final word.",funFact:"The person who shapes raw reporting into published text. 'Chefredakteur' (editor-in-chief) runs the whole operation. From French 'redacteur,' reflecting the strong French influence on German journalism vocabulary."},
{type:"teach",trg:"die Redakteurin",src:"editor (female)",pos:"noun",gender:"f",note:"Feminine noun. Redakteur + '-in.'\n'Chefredakteurin' (female editor-in-chief).",example:"A: Kennst du die neue Redakteurin?\nB: Ja, sie kommt vom Spiegel.\nA: Eine erfahrene Redakteurin.\nB: Genau, sie wird Chefredakteurin.",exampleSrc:"A: Do you know the new editor?\nB: Yes, she comes from Der Spiegel.\nA: An experienced editor.\nB: Exactly, she is becoming editor-in-chief.",funFact:"The standard feminine form. 'Chefredakteurin' = female editor-in-chief. German consistently forms feminine professional titles with -in. More women than ever hold Chefredakteurin positions in German media."},
{type:"mc",q:"Die Redaktion der FAZ hat einen neuen Redakteur. Wo arbeitet ein Redakteur?",opts:["In der Redaktion einer Zeitung oder Zeitschrift","In einer Druckerei oder Fabrik","In einer Universitaet als Professor","In einem Gericht als Richter"],ans:"In der Redaktion einer Zeitung oder Zeitschrift",hint:"Where a journalist or editor works to shape text for publication. Not a printing press or university."},
{type:"teach",trg:"der Leitartikel",src:"lead article, editorial",pos:"noun",gender:"m",note:"Masculine noun. Leit (leading) + Artikel.\nThe most important opinion piece.",example:"A: Hast du den Leitartikel gelesen?\nB: Ja, er ist sehr überzeugend.\nA: Der Leitartikel steht immer auf Seite eins.\nB: Er zeigt die Position der Zeitung.",exampleSrc:"A: Did you read the lead article?\nB: Yes, it is very convincing.\nA: The lead article is always on page one.\nB: It shows the position of the newspaper.",funFact:"The most important opinion piece, usually on page one. It 'leads' the newspaper's position on an issue. Different from a Kommentar: the Leitartikel represents the newspaper's official stance."},
{type:"teach",trg:"die Kolumne",src:"column (regular opinion piece)",pos:"noun",gender:"f",note:"Feminine noun. From Latin 'columna.'\nA regular, personal opinion piece.",example:"A: Schreibst du eine Kolumne?\nB: Ja, jeden Freitag über Medien.\nA: Eine Kolumne ist persönlicher als ein Leitartikel.\nB: Genau, ich schreibe über meine Meinung.",exampleSrc:"A: Do you write a column?\nB: Yes, every Friday about media.\nA: A column is more personal than a lead article.\nB: Exactly, I write about my opinion.",funFact:"A Kolumnist writes regularly on the same topic. Personal voice, consistent perspective. Different from Leitartikel: a Kolumne is personal, while a Leitartikel speaks for the newspaper."},
{type:"teach",trg:"die Rezension",src:"review (book, film, music)",pos:"noun",gender:"f",note:"Feminine noun. From Latin 'recensio.'\nFound in the Feuilleton section.",example:"A: Hast du die Rezension des neuen Films gelesen?\nB: Ja, sie war sehr kritisch.\nA: Wer hat die Rezension geschrieben?\nB: Die Filmkritikerin der Sueddeutschen.",exampleSrc:"A: Did you read the review of the new film?\nB: Yes, it was very critical.\nA: Who wrote the review?\nB: The film critic of the Sueddeutsche.",funFact:"Found in the Feuilleton (arts section) of German newspapers. 'Eine Buchrezension schreiben' (to write a book review). The Rezension is a respected form of cultural criticism in Germany."},
{type:"teach",trg:"der Herausgeber",src:"publisher, editor (of a book)",pos:"noun",gender:"m",note:"Masculine noun. Heraus (out) + Geber (giver).\n'Herausgegeben von...' (Published by...).",example:"A: Wer ist der Herausgeber dieses Buches?\nB: Professor Mueller ist der Herausgeber.\nA: Ein bekannter Herausgeber.\nB: Ja, er hat viele Buecher herausgegeben.",exampleSrc:"A: Who is the publisher of this book?\nB: Professor Mueller is the publisher.\nA: A well-known publisher.\nB: Yes, he has published many books.",funFact:"The person who 'gives out' a publication to the world. 'Herausgegeben von...' (Published by...) appears in every academic book. Different from Verlag (publishing house): the Herausgeber is a person, the Verlag is an institution."},
{type:"fb",s:"Der {1} steht immer auf Seite eins und zeigt die Position der Zeitung.",a:["Leitartikel"],opts:["Leserbrief","Leitartikel","Kommentar","Rezension"],hint:"The compound noun for the lead article that represents the newspaper's official stance. Leit + Artikel.",sSrc:"The lead article is always on page one and shows the newspaper's position."}
]},
{id:"deu_r26l3b",title:"Die Nachrichtenredaktion (Teil 2)",icon:"🏢",xp:15,board:true,steps:[
{type:"intro",title:"Die Nachrichtenredaktion (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"der Verlag",src:"publishing house",pos:"noun",gender:"m",note:"Masculine noun. From 'verlegen' (to publish).\nGermany is a Verlag powerhouse.",example:"A: Welcher Verlag hat das Buch publiziert?\nB: Der Suhrkamp Verlag.\nA: Ein grosser Verlag!\nB: Ja, einer der wichtigsten in Deutschland.",exampleSrc:"A: Which publisher published the book?\nB: Suhrkamp Verlag.\nA: A big publishing house!\nB: Yes, one of the most important in Germany.",funFact:"Germany is a publishing powerhouse: Suhrkamp, Fischer, Rowohlt, Hanser. 'Im Verlag erscheinen' (to be published by). The Frankfurt Book Fair (Frankfurter Buchmesse) is the world's largest. The Verlag decides what the world reads."},
{type:"teach",trg:"der Korrespondent",src:"correspondent (male)",pos:"noun",gender:"m",note:"Masculine noun. N-Deklination.\n'Auslandskorrespondent' (foreign correspondent).",example:"A: Wo ist unser Korrespondent?\nB: In Washington. Er berichtet über die Wahl.\nA: Ein Korrespondent lebt im Ausland?\nB: Ja, oft jahrelang.",exampleSrc:"A: Where is our correspondent?\nB: In Washington. He is reporting on the election.\nA: A correspondent lives abroad?\nB: Yes, often for years.",funFact:"N-Deklination: den Korrespondenten, dem Korrespondenten. The journalist stationed abroad who reports back. 'Auslandskorrespondent' (foreign correspondent) is one of the most prestigious roles in journalism."},
{type:"teach",trg:"die Korrespondentin",src:"correspondent (female)",pos:"noun",gender:"f",note:"Feminine noun. Korrespondent + '-in.'\nStandard feminine form.",example:"A: Unsere Korrespondentin in London berichtet.\nB: Sie ist seit fünf Jahren dort.\nA: Eine erfahrene Korrespondentin.\nB: Die beste, die wir haben.",exampleSrc:"A: Our correspondent in London is reporting.\nB: She has been there for five years.\nA: An experienced correspondent.\nB: The best we have.",funFact:"German TV news always credits 'unsere Korrespondentin in Washington' or 'unser Korrespondent in Moskau.' The role carries high prestige and requires deep cultural knowledge of the host country."},
{type:"teach",trg:"hervorheben",src:"to emphasize, to highlight",pos:"verb",gender:null,note:"Separable verb. Hervor (forth) + heben (to lift).\n'Einen Punkt hervorheben' (to emphasize a point).",example:"A: Was möchtest du hervorheben?\nB: Ich hebe die wichtigsten Fakten hervor.\nA: Gute Journalisten heben das Wesentliche hervor.\nB: Ja, ohne zu übertreiben.",exampleSrc:"A: What do you want to emphasize?\nB: I am highlighting the most important facts.\nA: Good journalists highlight what is essential.\nB: Yes, without exaggerating.",funFact:"Lifting something forth from the background so it stands out. Separable: 'Er hebt den Punkt hervor.' In journalism, knowing what to hervorheben and what to weglassen (leave out) is the art of editing."},
{type:"teach",trg:"erläutern",src:"to explain, to elucidate",pos:"verb",gender:null,note:"Regular verb. From 'lauter' (pure/clear).\nMore formal than 'erklären.'",example:"A: Können Sie das bitte erläutern?\nB: Gern. Ich erläutere den Hintergrund.\nA: Erlaeutern Sie bitte auch die Details.\nB: Natürlich. Ich erläutere alles Schritt für Schritt.",exampleSrc:"A: Could you please explain that?\nB: Gladly. I will explain the background.\nA: Please also explain the details.\nB: Of course. I will explain everything step by step.",funFact:"Making something 'clear.' More formal than 'erklären.' Academic and journalistic register. 'Erläuterung' (explanation/commentary) is the nominalized form. You erläutern complex topics; you erklären simple ones."},
{type:"teach",trg:"herausgeben",src:"to publish, to issue",pos:"verb",gender:null,note:"Separable verb. Heraus (out) + geben (to give).\nDer Herausgeber herausgibt.",example:"A: Wann gibt der Verlag das Buch heraus?\nB: Im Herbst. Sie geben es im Oktober heraus.\nA: Wer gibt die Zeitschrift heraus?\nB: Professor Berger gibt sie heraus.",exampleSrc:"A: When does the publisher release the book?\nB: In autumn. They are releasing it in October.\nA: Who publishes the journal?\nB: Professor Berger publishes it.",funFact:"Separable: 'Er gibt das Buch heraus.' The act of releasing something to the public. Related to Herausgeber (publisher/editor). 'Eine Pressemitteilung herausgeben' (to issue a press release) is standard media vocabulary."},
{type:"teach",trg:"darstellen",src:"to present, to portray",pos:"verb",gender:null,note:"Separable verb. Dar (there) + stellen (to place).\n'Einen Sachverhalt darstellen' (to present a matter).",example:"A: Wie stellt der Artikel das Thema dar?\nB: Er stellt es sehr einseitig dar.\nA: Die Darstellung ist entscheidend.\nB: Ja, gleiche Fakten, verschiedene Darstellung, anderes Ergebnis.",exampleSrc:"A: How does the article present the topic?\nB: It presents it very one-sidedly.\nA: The presentation is decisive.\nB: Yes, same facts, different presentation, different result.",funFact:"How you darstellen the facts changes the story. Same facts, different Darstellung, different conclusion. Separable: 'Er stellt es dar.' 'Die Darstellung' (the portrayal/presentation) is a key concept in media criticism."},
{type:"mc",q:"Gute Journalisten heben das Wesentliche hervor. Was bedeutet 'hervorheben'?",opts:["Etwas ausblenden und ignorieren","Etwas unterdrücken und verbergen","Etwas betonen und sichtbar machen","Etwas verharmlosen und herunterspielen"],ans:"Etwas betonen und sichtbar machen",hint:"Hervor (forth) + heben (to lift). Bringing something forward so it becomes prominent."},
{type:"teach",trg:"kritisieren",src:"to criticize",pos:"verb",gender:null,note:"Regular verb. From Greek 'kritikos.'\nKritik (noun) becomes kritisieren (verb).",example:"A: Darf man die Medien kritisieren?\nB: Natürlich! Das ist Meinungsfreiheit.\nA: Wie kritisiert man konstruktiv?\nB: Mit Fakten und Argumenten, nicht mit Emotionen.",exampleSrc:"A: Is it allowed to criticize the media?\nB: Of course! That is freedom of expression.\nA: How does one criticize constructively?\nB: With facts and arguments, not with emotions.",funFact:"Constructive criticism is valued in German public discourse. Kritisieren is not the same as 'meckern' (to complain). 'Berechtigte Kritik' (justified criticism) drives improvement. 'Unsachliche Kritik' (unfounded criticism) is dismissed."},
{type:"teach",trg:"ausgewogen",src:"balanced",pos:"adj",gender:null,note:"Adjective. Aus (out) + gewogen (weighed).\nThe journalistic ideal. Opposite of einseitig.",example:"A: Ist der Bericht ausgewogen?\nB: Ja, beide Seiten kommen zu Wort.\nA: Ausgewogene Berichterstattung ist selten.\nB: Aber sie ist das Ziel.",exampleSrc:"A: Is the report balanced?\nB: Yes, both sides have their say.\nA: Balanced reporting is rare.\nB: But it is the goal.",funFact:"All sides have been 'weighed out' equally. The opposite of einseitig. The journalistic ideal that every serious newspaper claims to pursue. 'Ausgewogenheit' (balance) is the nominalized form."},
{type:"teach",trg:"investigativ",src:"investigative",pos:"adj",gender:null,note:"Adjective. From Latin 'investigare' (to track).\n'Investigativer Journalismus' (investigative journalism).",example:"A: Was ist investigativer Journalismus?\nB: Tiefgehende Recherche über Monate.\nA: Deutschland hat starke investigative Medien.\nB: Der Spiegel und Correctiv zum Beispiel.",exampleSrc:"A: What is investigative journalism?\nB: In-depth research over months.\nA: Germany has strong investigative media.\nB: Der Spiegel and Correctiv, for example.",funFact:"Digging deep. Germany's investigative tradition uncovered the NSA spying scandal (through Der Spiegel) and contributed to the Wirecard fraud exposure. 'Investigative Recherche' takes months, sometimes years."},
{type:"teach",trg:"kontrovers",src:"controversial",pos:"adj",gender:null,note:"Adjective. From Latin 'controversia.'\n'Ein kontroverses Thema' (a controversial topic).",example:"A: Das Thema ist sehr kontrovers.\nB: Ja, die Meinungen gehen weit auseinander.\nA: Kontroverse Themen brauchen guten Journalismus.\nB: Stimmt, alle Seiten müssen gehört werden.",exampleSrc:"A: The topic is very controversial.\nB: Yes, opinions differ widely.\nA: Controversial topics need good journalism.\nB: True, all sides must be heard.",funFact:"A Kontroverse is a public disagreement. German media thrives on Kontroversen. 'Kontrovers diskutieren' (to discuss controversially). Political talk shows like 'Hart aber fair' live from kontroverse Themen."},
{type:"teach",trg:"sachkundig",src:"expert, knowledgeable",pos:"adj",gender:null,note:"Adjective. Sach (matter) + kundig (knowledgeable).\nStronger than 'informiert.'",example:"A: Ist der Kommentator sachkundig?\nB: Ja, er ist ein sachkundiger Experte.\nA: Sachkundige Kommentare sind wertvoll.\nB: Sie helfen, komplexe Themen zu verstehen.",exampleSrc:"A: Is the commentator knowledgeable?\nB: Yes, he is an expert commentator.\nA: Expert commentaries are valuable.\nB: They help understand complex topics.",funFact:"Knowing the Sache (subject matter). Stronger than 'informiert': sachkundig implies deep expertise built over years. 'Ein sachkundiger Beitrag' (an expert contribution) carries weight in German discourse."},
{type:"teach",trg:"öffentlich-rechtlich",src:"public-service (broadcasting)",pos:"adj",gender:null,note:"Compound adjective. Öffentlich (public) + rechtlich (legal).\nARD and ZDF are öffentlich-rechtlich.",example:"A: Was bedeutet öffentlich-rechtlich?\nB: Vom Staat unabhängig, aber von Bürgern finanziert.\nA: ARD und ZDF sind öffentlich-rechtlich?\nB: Ja, und Deutschlandfunk auch.",exampleSrc:"A: What does public-service mean?\nB: Independent from the state, but funded by citizens.\nA: ARD and ZDF are public-service?\nB: Yes, and Deutschlandfunk too.",funFact:"ARD and ZDF are öffentlich-rechtlich. Funded by citizens through the Rundfunkbeitrag, independent from government and advertisers. A uniquely German model designed to prevent the media manipulation that enabled the Nazi regime."},
{type:"tip",title:"Partizipialattribute: Der deutsche Satz-im-Wort",text:"German can pack an entire relative clause BEFORE a noun:\n\nPartizip I (active, ongoing): der berichtende Journalist = der Journalist, der berichtet\nPartizip II (passive, completed): der veröffentlichte Bericht = der Bericht, der veröffentlicht wurde\nExtended: die von der Regierung geplante Maßnahme = die Maßnahme, die von der Regierung geplant wurde\nWith 'zu' (gerundive): die zu prüfende Aussage = die Aussage, die geprüft werden muss\n\nThese constructions appear everywhere in newspapers, academic texts, and legal documents. They compress information.",deepDive:{title:"Why Partizipialattribute?",text:"Written German loves compression. A relative clause ('der Bericht, der veröffentlicht wurde') takes many words. A Partizipialattribut ('der veröffentlichte Bericht') says the same in fewer words. Newspapers use them constantly because space is limited. Academic texts use them for precision. Learning to read Partizipialattribute is essential for reading German media fluently."}},
{type:"verb_table",title:"Partizipialattribute: Bildungsmuster",groups:[{label:"Partizip I (aktiv, laufend)",rows:[{pronoun:"berichten",form:"der berichtende Journalist",src:"the reporting journalist"},{pronoun:"wachsen",form:"die wachsende Kritik",src:"the growing criticism"},{pronoun:"lesen",form:"der lesende Student",src:"the reading student"}]},{label:"Partizip II (passiv, abgeschlossen)",rows:[{pronoun:"veröffentlichen",form:"der veröffentlichte Bericht",src:"the published report"},{pronoun:"betreffen",form:"die betroffenen Bürger",src:"the affected citizens"},{pronoun:"recherchieren",form:"die recherchierten Fakten",src:"the researched facts"}]},{label:"Partizip I + zu (Gerundiv: muss getan werden)",rows:[{pronoun:"prüfen",form:"die zu prüfende Aussage",src:"the statement to be examined"},{pronoun:"loesen",form:"das zu loesende Problem",src:"the problem to be solved"},{pronoun:"beachten",form:"die zu beachtenden Regeln",src:"the rules to be observed"}]}],note:"Partizip I: stem + d + adjective ending. Partizip II: ge- + stem + t/en + adjective ending. Gerundive: zu + Partizip I + adjective ending."},
{type:"mc",q:"Mia sagt: 'Der veröffentlichte Bericht ist einseitig.' Was ist 'der veröffentlichte Bericht'?",opts:["Ein Partizipialattribut: der Bericht, der veröffentlicht wurde","Ein gewöhnliches attributives Adjektiv, das den Bericht beschreibt","Eine Konjunktiv-II-Form für irreale Sätze","Eine Passivkonstruktion mit werden und Hilfsverb"],ans:"Ein Partizipialattribut: der Bericht, der veröffentlicht wurde",hint:"A past verb form is placed before the noun to describe it. Ask: what structure compresses a relative clause into a single pre-noun construction?"},
{type:"fb",s:"Die von der Regierung {1} Maßnahme betrifft alle Bürger.",a:["geplante"],opts:["geplant","geplante","planen","planende"],hint:"Use the Partizip II of 'planen' as an adjective before a feminine noun. Choose the correct adjectival ending.",sSrc:"The measure planned by the government affects all citizens."},
{type:"mc",q:"Was bedeutet 'erläutern'?",opts:["editor (female)","to explain, to elucidate","controversial","lead article, editorial"],ans:"to explain, to elucidate",hint:"Related to lauter (clear). To make a topic clearer with more detail."},
{type:"fb",s:"Wie sagt man 'to publish, to issue' auf Deutsch? {1}",a:["herausgeben"],opts:["der Verlag","herausgeben","kritisieren","der Herausgeber"],hint:"Heraus- (out) + geben (to give). To release a publication to the public.",sSrc:"How do you say 'to publish, to issue' in German?"},
{type:"mc",q:"Was bedeutet 'darstellen'?",opts:["to explain, to elucidate","editor (male)","editorial office, newsroom","to present, to portray"],ans:"to present, to portray",hint:"Dar- (there) + stellen (to place). To put information before an audience."},
{type:"fb",s:"Darf man die Medien {1}?",a:["kritisieren"],opts:["kontrovers","kritisieren","erläutern","sachkundig"],hint:"Cognate of English 'criticize.' Greek: krinein (to judge carefully).",sSrc:"Is it allowed to criticize the media?"},
{type:"mc",q:"Was bedeutet 'kontrovers'?",opts:["column (regular opinion piece)","controversial","to present, to portray","editorial office, newsroom"],ans:"controversial",hint:"Latin: contra + vertere (to turn against). A topic people strongly disagree on."},
{type:"fb",s:"Ist der Kommentator {1}?",a:["sachkundig"],opts:["die Redaktion","investigativ","herausgeben","sachkundig"],hint:"Sache (subject) + kundig (knowledgeable). Expert in a particular field.",sSrc:"Is the commentator knowledgeable?"}
]},
{id:"deu_r26l4",title:"Man kann das auch anders sagen",icon:"🔄",xp:15,board:true,steps:[
{type:"intro",title:"Man kann das auch anders sagen",desc:"German passive alternatives and adversative clauses. Learn elegant ways to express actions without using the standard passive, and contrast opposing viewpoints.",goals:["Master passive alternatives (sich lassen, sein + zu, -bar)","Learn adversative clauses (während, wohingegen, anstatt dass)","Discuss media ethics and press conferences"]},
{type:"story",speaker:"narrator",mood:"observing",art:"de-ber-office-screen",trg:"Verumius sitzt an seinem Schreibtisch. Auf dem Bildschirm: eine Pressekonferenz, live. Die Ministerin spricht. Die Journalisten fragen. Verumius hoert etwas Neues in der Sprache.",src:"Verumius sits at his desk. On the screen: a press conference, live. The minister speaks. The journalists ask questions. Verumius hears something new in the language."},
{type:"story",speaker:"verumius",mood:"curious",art:"de-ber-office-screen",trg:"'Das lässt sich nicht bestätigen.' 'Die Situation ist kaum überschaubar.' 'Anstatt dass man die Betroffenen fragt...' Sie sagen nie direkt: 'Wir können das nicht.' Sie sagen es elegant. Anders.",src:"'That cannot be confirmed.' 'The situation is barely manageable.' 'Instead of asking those affected...' They never say directly: 'We cannot do that.' They say it elegantly. Differently."},
{type:"story",speaker:"narrator",mood:"intellectual",art:"de-ber-office-screen",trg:"Die Sprache der Pressekonferenz ist eine eigene Welt. Passiv ohne Passiv. Kritik ohne direkten Angriff. Verumius will das auch können.",src:"The language of the press conference is a world of its own. Passive without passive. Criticism without direct attack. Verumius wants to master that too."},
{type:"teach",trg:"die Pressekonferenz",src:"press conference",pos:"noun",gender:"f",note:"Feminine noun. Presse + Konferenz.\n'Auf der Pressekonferenz' (at the press conference).",example:"A: Wann ist die Pressekonferenz?\nB: Um 14 Uhr im Kanzleramt.\nA: Wer spricht auf der Pressekonferenz?\nB: Die Ministerin erklärt das neue Gesetz.",exampleSrc:"A: When is the press conference?\nB: At 2 PM in the chancellery.\nA: Who is speaking at the press conference?\nB: The minister explains the new law.",funFact:"Where officials speak and journalists ask tough questions. German Pressekonferenzen are formal. 'Die Bundespressekonferenz' in Berlin is unique: it is organized by journalists themselves, not by the government."},
{type:"teach",trg:"die Pressemitteilung",src:"press release",pos:"noun",gender:"f",note:"Feminine noun. Presse + Mitteilung (communication).\nOne-way communication, no questions.",example:"A: Haben wir eine Pressemitteilung bekommen?\nB: Ja, vom Ministerium.\nA: Eine Pressemitteilung ist keine Nachricht.\nB: Richtig, sie ist die kontrollierte Version.",exampleSrc:"A: Did we receive a press release?\nB: Yes, from the ministry.\nA: A press release is not news.\nB: Right, it is the controlled version.",funFact:"One-way communication: the organization tells the media what it wants known. No questions allowed. The controlled version of a Pressekonferenz. Good journalists treat Pressemitteilungen as starting points, not final products."},
{type:"teach",trg:"die Nachrichtenagentur",src:"news agency",pos:"noun",gender:"f",note:"Feminine noun. Nachrichten + Agentur.\nDPA is Germany's biggest.",example:"A: Woher kommt diese Nachricht?\nB: Von der DPA, der Deutschen Presse-Agentur.\nA: Was macht eine Nachrichtenagentur?\nB: Sie liefert Nachrichten an Zeitungen und Sender.",exampleSrc:"A: Where does this news come from?\nB: From the DPA, the German Press Agency.\nA: What does a news agency do?\nB: It supplies news to newspapers and broadcasters.",funFact:"DPA (Deutsche Presse-Agentur) is Germany's biggest. Reuters, AP, AFP are international agencies. They supply raw news to newspapers and TV stations. Most news you read starts at a Nachrichtenagentur."},
{type:"teach",trg:"die Informationsquelle",src:"information source",pos:"noun",gender:"f",note:"Feminine noun. Information + Quelle (source).\n'Zuverlässiige Quellen' (reliable sources).",example:"A: Was ist deine Informationsquelle?\nB: Mehrere zuverlässiige Informationsquellen.\nA: Gute Journalisten haben viele Informationsquellen.\nB: Ja, und sie schützen ihre Quellen.",exampleSrc:"A: What is your information source?\nB: Several reliable information sources.\nA: Good journalists have many information sources.\nB: Yes, and they protect their sources.",funFact:"In journalism, your sources make or break your credibility. 'Quellenschutz' (source protection) is sacred. German law protects journalists from having to reveal their Informationsquellen. 'Zuverlässiige Informationsquellen' is the gold standard."},
{type:"mc",q:"Die DPA liefert Nachrichten an Zeitungen und Sender. Was ist die DPA?",opts:["Eine Nachrichtenagentur","Eine Boulevardzeitung","Ein öffentlich-rechtlicher Rundfunk","Eine Pressemitteilung"],ans:"Eine Nachrichtenagentur",hint:"The DPA (Deutsche Presse-Agentur) is Germany's biggest organization that supplies raw news to media outlets."},
{type:"teach",trg:"die Reichweite",src:"reach, circulation",pos:"noun",gender:"f",note:"Feminine noun. Reich (reach) + Weite (width).\nIn digital media: how many people see content.",example:"A: Wie gross ist die Reichweite dieser Zeitung?\nB: Etwa zwei Millionen Leser.\nA: Und online?\nB: Online ist die Reichweite noch groesser.",exampleSrc:"A: How large is this newspaper's reach?\nB: About two million readers.\nA: And online?\nB: Online the reach is even larger.",funFact:"In print: circulation. In digital media: how many people see your content. Social media lives and dies by Reichweite. 'Die organische Reichweite' (organic reach) vs. 'bezahlte Reichweite' (paid reach) is a key distinction."},
{type:"teach",trg:"die Zielgruppe",src:"target audience",pos:"noun",gender:"f",note:"Feminine noun. Ziel (target) + Gruppe (group).\nEvery medium has its Zielgruppe.",example:"A: Wer ist die Zielgruppe dieser Sendung?\nB: Junge Erwachsene zwischen 18 und 30.\nA: Jedes Medium hat eine andere Zielgruppe.\nB: Ja, und die Zielgruppe bestimmt den Inhalt.",exampleSrc:"A: Who is the target audience of this program?\nB: Young adults between 18 and 30.\nA: Every medium has a different target audience.\nB: Yes, and the target audience determines the content.",funFact:"Every medium has its Zielgruppe. Knowing yours determines how you write, what you cover, and which stories you prioritize. 'Die Zielgruppe ansprechen' (to address the target audience) is the core of media strategy."},
{type:"teach",trg:"die Privatsphaere",src:"privacy",pos:"noun",gender:"f",note:"Feminine noun. Privat + Sphaere (sphere).\nGerman privacy law is among the strictest.",example:"A: Schuetzt das Gesetz die Privatsphaere?\nB: Ja, in Deutschland ist die Privatsphaere sehr wichtig.\nA: Dürfen Journalisten alles veröffentlichen?\nB: Nein, die Privatsphaere hat Grenzen.",exampleSrc:"A: Does the law protect privacy?\nB: Yes, in Germany privacy is very important.\nA: May journalists publish everything?\nB: No, privacy has limits.",funFact:"German privacy law is among the strictest in the world. The Privatsphaere is a legal and cultural fortress. Even public figures have a Privatsphaere that media must respect. Paparazzi culture is far less accepted in Germany than in the UK or US."},
{type:"teach",trg:"der Datenschutz",src:"data protection",pos:"noun",gender:"m",note:"Masculine noun. Daten (data) + Schutz (protection).\nGermany led the EU's DSGVO (GDPR).",example:"A: Was ist Datenschutz?\nB: Der Schutz persönlicher Daten.\nA: Deutschland nimmt Datenschutz sehr ernst.\nB: Ja, die DSGVO kam aus europaeischer Initiative.",exampleSrc:"A: What is data protection?\nB: The protection of personal data.\nA: Germany takes data protection very seriously.\nB: Yes, the GDPR came from European initiative.",funFact:"Germany led the EU's DSGVO (GDPR). 'Datenschutzbeauftragter' (data protection officer) is a real job title. Privacy is serious business in Germany. Every company needs a Datenschutzerklärung (privacy policy)."},
{type:"fb",s:"Die {1} ist das Recht auf den Schutz persönlicher Daten.",a:["Privatsphaere"],opts:["Pressefreiheit","Privatsphaere","Reichweite","Zielgruppe"],hint:"The feminine noun for your personal sphere that law protects. Privat + Sphaere.",sSrc:"Privacy is the right to the protection of personal data."}
]},
{id:"deu_r26l4b",title:"Man kann das auch anders sagen (Teil 2)",icon:"🔄",xp:15,board:true,steps:[
{type:"intro",title:"Man kann das auch anders sagen (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"aufdecken",src:"to uncover, to expose",pos:"verb",gender:null,note:"Separable verb. Auf (up) + decken (to cover).\nThe verb of investigative journalism.",example:"A: Was hat der Journalist aufgedeckt?\nB: Einen Korruptionsskandal.\nA: Investigativer Journalismus deckt Misstände auf.\nB: Ja, das ist seine wichtigste Aufgabe.",exampleSrc:"A: What did the journalist uncover?\nB: A corruption scandal.\nA: Investigative journalism uncovers abuses.\nB: Yes, that is its most important task.",funFact:"Lifting the cover off something hidden. Separable: 'Er deckt den Skandal auf.' The verb of investigative journalism. 'Aufgedeckt!' (Uncovered!) is a powerful one-word headline."},
{type:"teach",trg:"enthueleln",src:"to reveal, to unveil",pos:"verb",gender:null,note:"Regular verb. Ent- (un-) + huellen (to wrap).\nStronger than aufdecken.",example:"A: Die Zeitung hat geheime Dokumente enthuellt.\nB: Eine sensationelle Enthuellung!\nA: Enthueleln ist stärker als aufdecken.\nB: Ja, es bedeutet: etwas absichtlich Verborgenes zeigen.",exampleSrc:"A: The newspaper revealed secret documents.\nB: A sensational revelation!\nA: Revealing is stronger than uncovering.\nB: Yes, it means: showing something deliberately concealed.",funFact:"Removing the Huelle (wrapping). Stronger than aufdecken: implies something deliberately concealed. 'Enthuellung' (revelation) is the noun. 'Enthuelungsjournalismus' (revelatory journalism) shakes institutions."},
{type:"teach",trg:"dementieren",src:"to deny (officially)",pos:"verb",gender:null,note:"Regular verb. From French 'dementir.'\nOfficial denial by politicians or institutions.",example:"A: Hat der Minister die Vorwuerfe dementiert?\nB: Ja, er dementiert alles.\nA: Wenn Politiker dementieren, recherchieren Journalisten weiter.\nB: Genau, ein Dementi ist oft ein Signal.",exampleSrc:"A: Did the minister deny the accusations?\nB: Yes, he denies everything.\nA: When politicians deny, journalists investigate harder.\nB: Exactly, a denial is often a signal.",funFact:"Official denial. When politicians dementieren, journalists investigate harder. 'Das Dementi' (the denial) is the noun. A famous journalism rule: 'Ein Dementi ist eine Nachricht' (A denial is news in itself)."},
{type:"teach",trg:"unterdrücken",src:"to suppress",pos:"verb",gender:null,note:"Not separable. Unter (under) + drücken (to press).\n'Informationen unterdrücken' (to suppress information).",example:"A: Kann die Regierung Nachrichten unterdrücken?\nB: In Demokratien ist das verboten.\nA: Aber manche versuchen es.\nB: Ja, deshalb brauchen wir unabhängige Medien.",exampleSrc:"A: Can the government suppress news?\nB: In democracies that is forbidden.\nA: But some try.\nB: Yes, that is why we need independent media.",funFact:"Pressing something down so it stays hidden. Not separable. What authoritarian regimes do to inconvenient truths. 'Unterdrückte Informationen' (suppressed information) eventually surface. Truth is difficult to unterdrücken permanently."},
{type:"teach",trg:"zurückweisen",src:"to reject, to dismiss",pos:"verb",gender:null,note:"Separable verb. Zurück (back) + weisen (to direct).\n'Kritik zurückweisen' (to reject criticism).",example:"A: Hat die Firma die Kritik zurückgewiesen?\nB: Ja, sie weist alle Vorwuerfe zurück.\nA: Zurückweisen ist formeller als ablehnen.\nB: Ja, es klingt diplomatisch aber bestimmt.",exampleSrc:"A: Did the company reject the criticism?\nB: Yes, it dismisses all accusations.\nA: Zurückweisen is more formal than ablehnen.\nB: Yes, it sounds diplomatic but firm.",funFact:"Pushing criticism back where it came from. Separable: 'Sie weist die Kritik zurück.' Formal, diplomatic language. Weaker than 'widersprechen' (to contradict) but stronger than simply 'ablehnen' (to decline)."},
{type:"teach",trg:"sensibilisieren",src:"to sensitize, to raise awareness",pos:"verb",gender:null,note:"Regular verb. Sensibel + -isieren.\n'Für etwas sensibilisieren' (to raise awareness of).",example:"A: Wie kann man für Medienkompetenz sensibilisieren?\nB: Durch Bildung und Beispiele.\nA: Schulen sollten dafür sensibilisieren.\nB: Ja, je früher, desto besser.",exampleSrc:"A: How can you raise awareness of media literacy?\nB: Through education and examples.\nA: Schools should raise awareness of it.\nB: Yes, the earlier, the better.",funFact:"Making people sensitive to an issue. 'Sensibilisierungskampagne' (awareness campaign) is a common compound. Media literacy education aims to sensibilisieren, not to indoctrinate. The goal: informed, critical media consumers."},
{type:"mc",q:"Die Journalistin deckt einen Skandal auf. Was bedeutet 'aufdecken'?",opts:["Einen Artikel veröffentlichen","Eine Pressemitteilung lesen","Etwas Verborgenes entdecken und zeigen","Einen Kommentar schreiben"],ans:"Etwas Verborgenes entdecken und zeigen",hint:"Auf (up) + decken (to cover). Lifting the cover off something hidden. The essential verb of investigative journalism."},
{type:"teach",trg:"irreführend",src:"misleading",pos:"adj",gender:null,note:"Adjective. Irre (astray) + führend (leading).\nPartizip I used as adjective.",example:"A: Die Schlagzeile ist irreführend.\nB: Ja, sie führt die Leser in die Irre.\nA: Irreführende Schlagzeilen sind ein grosses Problem.\nB: Sie verzerren die Wahrnehmung.",exampleSrc:"A: The headline is misleading.\nB: Yes, it leads the readers astray.\nA: Misleading headlines are a big problem.\nB: They distort perception.",funFact:"Leading readers astray. A Partizip I used as adjective. The headlines lead (führen) you into error (Irre). 'Irreführende Werbung' (misleading advertising) is illegal in Germany under the UWG (Unfair Competition Act)."},
{type:"teach",trg:"fragwürdig",src:"questionable, dubious",pos:"adj",gender:null,note:"Adjective. Frag (question) + würdig (worthy).\nNot proven wrong, but suspicious.",example:"A: Seine Methoden sind fragwürdig.\nB: Ja, sie verdienen genaue Prüfung.\nA: Fragwürdig heißt nicht falsch.\nB: Nein, aber es heißt: genau hinschauen.",exampleSrc:"A: His methods are questionable.\nB: Yes, they deserve close examination.\nA: Questionable does not mean wrong.\nB: No, but it means: look closely.",funFact:"Worth questioning. Not proven wrong, but suspicious enough to deserve scrutiny. The -würdig suffix appears in many evaluative adjectives: glaubwürdig (credible), fragwürdig (questionable), denkwürdig (memorable)."},
{type:"teach",trg:"reisserisch",src:"sensationalist",pos:"adj",gender:null,note:"Adjective. From 'reissen' (to tear/rip).\nThe mark of tabloid journalism.",example:"A: Die Überschrift ist reisserisch.\nB: Ja, sie will Emotionen wecken.\nA: Reisserische Medien übertreiben.\nB: Serioese Medien bleiben sachlich.",exampleSrc:"A: The headline is sensationalist.\nB: Yes, it wants to stir emotions.\nA: Sensationalist media exaggerate.\nB: Reputable media stay factual.",funFact:"Headlines that 'rip' at your emotions. The word itself sounds aggressive. The mark of tabloid journalism. 'Reisserische Schlagzeilen' (sensationalist headlines) sacrifice accuracy for attention."},
{type:"teach",trg:"sensationell",src:"sensational",pos:"adj",gender:null,note:"Adjective. From French 'sensationnel.'\nCan be positive or negative.",example:"A: Die Entdeckung ist sensationell!\nB: Aber ist sie auch wahr?\nA: Sensationell klingt positiv.\nB: In der Medienkritik oft negativ: zu viel Hype.",exampleSrc:"A: The discovery is sensational!\nB: But is it also true?\nA: Sensational sounds positive.\nB: In media criticism often negative: too much hype.",funFact:"Can be positive (amazing!) or negative (exaggerated!). In media criticism, sensationell usually implies too much hype and too little substance. 'Sensationsjournalismus' (sensationalist journalism) prioritizes shock value."},
{type:"teach",trg:"boulevardesk",src:"tabloid-style",pos:"adj",gender:null,note:"Adjective. From Boulevard (French: broad street).\n'Boulevardeske Berichterstattung' (tabloid-style reporting).",example:"A: Ist das serioes oder boulevardesk?\nB: Eher boulevardesk. Grosse Bilder, wenig Inhalt.\nA: Die Bild-Zeitung ist boulevardesk.\nB: Ja, sie ist Deutschlands groesste Boulevardzeitung.",exampleSrc:"A: Is that reputable or tabloid-style?\nB: Rather tabloid-style. Big pictures, little content.\nA: The Bild newspaper is tabloid-style.\nB: Yes, it is Germany's largest tabloid.",funFact:"The Boulevardpresse (tabloid press) prioritizes sensation over substance. Bild-Zeitung is Germany's largest Boulevardzeitung with millions of daily readers. Named after French boulevards where newspapers were sold to passersby."},
{type:"teach",trg:"populistisch",src:"populist",pos:"adj",gender:null,note:"Adjective. From Latin 'populus' (people).\nAlmost always negative in German media criticism.",example:"A: Ist das populistische Rhetorik?\nB: Ja, er spricht für 'das Volk' gegen 'die Eliten.'\nA: Populistisch klingt negativ.\nB: In der deutschen Medienkritik fast immer.",exampleSrc:"A: Is that populist rhetoric?\nB: Yes, he speaks for 'the people' against 'the elites.'\nA: Populist sounds negative.\nB: In German media criticism, almost always.",funFact:"Claiming to speak for 'das Volk' (the people) against elites. In German media criticism, populistisch is almost always negative. Germany's historical experience with demagogues makes the word especially charged."},
{type:"tip",title:"Passivalternativen: Drei elegante Wege",text:"German has three elegant alternatives to the standard werden-passive. All are shorter, more natural, and very common in media and academic texts.\n\n- sich lassen with an infinitive expresses possibility: Das lässt sich erklären (That can be explained).\n- sein with zu and an infinitive often implies necessity: Das ist zu beweisen (That must be proven).\n- The -bar adjective is the most compact form: erklärbar (explainable), überprüfbar (verifiable), nachvollziehbar (comprehensible).\n\nIn newspaper writing and academic texts, these alternatives sound more natural than the werden-passive.",deepDive:{title:"Which alternative, when?",text:"sich lassen + Inf emphasizes possibility: 'Das lässt sich machen' (That can be done). sein + zu + Inf often implies necessity or obligation: 'Das ist noch zu prüfen' (That still needs to be checked). The -bar adjective is the most compact: 'nachvollziehbar' (comprehensible), 'überprüfbar' (verifiable). In newspaper writing, these alternatives sound more natural than the werden-passive."}},
{type:"tip",title:"Adversativsaetze: Kontraste ausdrücken",text:"German has several connectors for contrast and opposition:\n\nwährend: Während serioese Medien recherchieren, verbreiten andere Fake News.\n(While serious media research, others spread fake news.)\n\nwohingegen: Die FAZ berichtet ausführlich, wohingegen die Bild verkürzt.\n(The FAZ reports in detail, whereas Bild shortens.)\n\nanstatt dass: Anstatt dass er recherchiert, kopiert er nur.\n(Instead of researching, he only copies.)\n\nstatt ... zu: Statt gründlich zu recherchieren, übernahm er die Meldung.\n(Instead of researching thoroughly, he adopted the report.)\n\nThese adversative clauses are indispensable for media criticism.",deepDive:{title:"Contrast vs. concession",text:"Adversativsaetze (während, wohingegen) express pure contrast: A does X while B does Y. Konzessivsaetze (obwohl, trotzdem) express concession: Despite A, B happens. In media criticism, Adversativsaetze compare practices: 'Während serioese Medien Quellen prüfen, verbreitet die Boulevardpresse ungeprüfte Meldungen.' The contrast is the argument."}},
{type:"mc",q:"Die vom Journalisten recherchierten Fakten lassen sich leicht überprüfen. Welche Grammatik-Konstruktionen kommen vor?",opts:["Partizipialattribut + Passivalternative","Nur das Partizipialattribut allein","Nur die Passivalternative allein","Standard-Passiv mit werden und Partizip II"],ans:"Partizipialattribut + Passivalternative",hint:"'Die vom Journalisten recherchierten Fakten': a compressed relative clause before the noun. 'Lassen sich überprüfen': a passive alternative without werden."},
{type:"fb",s:"Das {1} sich nicht so einfach erklären.",a:["lässt"],opts:["kann","lässt","wird","ist"],hint:"The sich lassen + Infinitiv pattern for expressing possibility. Which verb form completes it?",sSrc:"That cannot be explained so easily."},
{type:"drag_fill",s:"{1} die Qualitaetszeitung gründlich recherchiert, verbreitet die Boulevardpresse {2} Schlagzeilen.",blanks:{"1":"Während","2":"reisserische"},pool:["Während","reisserische","Weil","serioese","Obwohl","investigative"],hint:"A contrast: while quality papers research thoroughly, tabloids spread sensationalist headlines. First blank is the adversative connector.",sSrc:"While the quality newspaper researches thoroughly, the tabloid press spreads sensationalist headlines."},
{type:"mc",q:"Was bedeutet 'enthueleln'?",opts:["populist","sensationalist","information source","to reveal, to unveil"],ans:"to reveal, to unveil",hint:"Ent- (removing) + Hulle (cover). To strip away a cover from secrets."},
{type:"fb",s:"Wenn Politiker {1}, recherchieren Journalisten weiter.",a:["dementieren"],opts:["sensationell","unterdrücken","die Privatsphaere","dementieren"],hint:"From Dementi (denial). To officially and publicly deny a claim.",sSrc:"When politicians deny, journalists investigate harder."},
{type:"mc",q:"Was bedeutet 'unterdrücken'?",opts:["misleading","data protection","to suppress","populist"],ans:"to suppress",hint:"Unter- (under) + drucken (to press). To press down and silence opposition."},
{type:"fb",s:"{1} ist formeller als ablehnen.",a:["zurückweisen"],opts:["unterdrücken","zurückweisen","die Zielgruppe","die Informationsquelle"],hint:"Zuruck- (back) + weisen (to direct). To firmly send a claim back.",sSrc:"Zurückweisen is more formal than ablehnen."},
{type:"mc",q:"Was bedeutet 'sensibilisieren'?",opts:["information source","misleading","to sensitize, to raise awareness","data protection"],ans:"to sensitize, to raise awareness",hint:"From sensibel (sensitive). To make people more aware of an issue."},
{type:"fb",s:"Die Entdeckung ist {1}!",a:["sensationell"],opts:["unterdrücken","sensationell","die Reichweite","enthueleln"],hint:"Cognate of English 'sensational.' Causing a strong public reaction.",sSrc:"The discovery is sensational!"},
{type:"mc",q:"Welches Adjektiv beschreibt vereinfachende politische Rhetorik?",opts:["sensationalist","to reveal, to unveil","news agency","populist"],ans:"populist",hint:"Latin: populus (people). Rhetoric that oversimplifies to win mass appeal."}
]},
{id:"deu_r26l5",title:"Die andere Seite",icon:"\uD83D\uDDE3\uFE0F",xp:15,board:true,steps:[
{type:"intro",title:"Die andere Seite",desc:"Verumius joins the media debate. All three grammar constructs come together: Partizipialattribute, passive alternatives, and adversative clauses.",goals:["Join a German media debate","Practice all three grammar constructs together","Evaluate the reliability of media"]},
{type:"story",speaker:"narrator",mood:"triumphant",trg:"Nächster Tag. Gleiche Küche. Gleiche Kollegen. Mia beginnt erneut: 'Also, was denkt ihr heute über den Artikel?'",src:"Next day. Same kitchen. Same colleagues. Mia starts again: 'So, what do you think about the article today?'"},
{type:"story",speaker:"verumius",mood:"confident",trg:"Ich habe gestern Abend weitergelesen. Die recherchierten Fakten stimmen. Aber die Darstellung ist tendenzioes. Während der Autor die eine Seite ausführlich zitiert, kommen die Betroffenen kaum zu Wort. Das lässt sich leicht überprüfen.",src:"I continued reading yesterday evening. The researched facts are correct. But the portrayal is biased. While the author quotes one side extensively, those affected barely get a word in. That can easily be verified."},
{type:"story",speaker:"narrator",mood:"impressed",trg:"Stille am Tisch. Dann nickt Mia langsam. Ein Kollege sagt: 'Guter Punkt.' Verumius hat sich seinen Platz in einer deutschen Debatte verdient.",src:"Silence at the table. Then Mia nods slowly. A colleague says: 'Good point.' Verumius has earned his place in a German intellectual debate."},
{type:"story",speaker:"mia",mood:"approving",trg:"Siehst du? Man muss nur beide Seiten lesen. Die zu prüfende Frage ist immer: Wer profitiert von dieser Darstellung?",src:"See? You just have to read both sides. The question that needs examining is always: Who benefits from this portrayal?"},
{type:"teach",trg:"der Hintergrund",src:"background",pos:"noun",gender:"m",note:"Masculine noun. Hinter (behind) + Grund (ground/reason).\nWhat lies behind the visible story.",example:"A: Was ist der Hintergrund dieses Artikels?\nB: Der Hintergrund ist ein politischer Skandal.\nA: Vor diesem Hintergrund ergibt alles Sinn.\nB: Genau. Ohne Hintergrund versteht man nichts.",exampleSrc:"A: What is the background of this article?\nB: The background is a political scandal.\nA: Against this background, everything makes sense.\nB: Exactly. Without background, you understand nothing.",funFact:"Hinter (behind) + Grund (ground/reason). What lies behind the visible story. 'Vor diesem Hintergrund' (against this background) is one of the most common phrases in German media analysis. A Hintergrundbericht provides context beyond headlines."},
{type:"teach",trg:"der Interessenkonflikt",src:"conflict of interest",pos:"noun",gender:"m",note:"Masculine noun. Interessen (interests) + Konflikt.\nWhen a journalist's sources have hidden agendas.",example:"A: Hat der Autor einen Interessenkonflikt?\nB: Ja, er arbeitet für die Firma, über die er schreibt.\nA: Das ist ein klarer Interessenkonflikt.\nB: Solche Konflikte muss man offenlegen.",exampleSrc:"A: Does the author have a conflict of interest?\nB: Yes, he works for the company he writes about.\nA: That is a clear conflict of interest.\nB: Such conflicts must be disclosed.",funFact:"Interessen (interests) + Konflikt (conflict). When hidden agendas compromise objectivity. 'Einen Interessenkonflikt offenlegen' (to disclose a conflict of interest) is an ethical duty in journalism. Transparency prevents Manipulation."},
{type:"teach",trg:"die Medienlandschaft",src:"media landscape",pos:"noun",gender:"f",note:"Feminine noun. Medien + Landschaft (landscape).\nMedia as a terrain you navigate.",example:"A: Wie sieht die deutsche Medienlandschaft aus?\nB: Sie ist vielfaeltig: öffentlich-rechtlich, privat, digital.\nA: Die Medienlandschaft verändert sich ständig.\nB: Ja, besonders durch soziale Medien.",exampleSrc:"A: What does the German media landscape look like?\nB: It is diverse: public, private, digital.\nA: The media landscape is constantly changing.\nB: Yes, especially through social media.",funFact:"Medien + Landschaft (landscape). The metaphor paints media as a terrain you navigate. Germany's Medienlandschaft includes ARD, ZDF, private broadcasters, national and regional newspapers, and a growing digital sector. No other country has quite this mix."},
{type:"mc",q:"Der Journalist hat einen Interessenkonflikt, weil er für die Firma arbeitet, über die er schreibt. Was ist ein Interessenkonflikt?",opts:["Wenn persönliche Interessen die Objektivitaet gefaehrden","Wenn ein Journalist zu viele Artikel schreibt","Wenn eine Zeitung eine hohe Auflage hat","Wenn ein Korrespondent ins Ausland reist"],ans:"Wenn persönliche Interessen die Objektivitaet gefaehrden",hint:"When hidden agendas compromise objectivity. A conflict between personal interests and professional duty."},
{type:"teach",trg:"die Stellungnahme",src:"statement, position paper",pos:"noun",gender:"f",note:"Feminine noun. Stellung (position) + Nahme (taking).\nTaking a position on an issue.",example:"A: Hat die Regierung eine Stellungnahme abgegeben?\nB: Ja, die offizielle Stellungnahme kam heute Morgen.\nA: Was steht in der Stellungnahme?\nB: Sie weisen die Vorwuerfe zurück.",exampleSrc:"A: Did the government issue a statement?\nB: Yes, the official statement came this morning.\nA: What does the statement say?\nB: They reject the accusations.",funFact:"Stellung (position) + Nahme (taking). The formal act of taking a position. 'Eine offizielle Stellungnahme abgeben' (to issue an official statement) is the standard phrase. Politicians, companies, and institutions all give Stellungnahmen."},
{type:"teach",trg:"die Tatsache",src:"fact",pos:"noun",gender:"f",note:"Feminine noun. Tat (deed) + Sache (thing).\nA fact: something that was actually done or happened.",example:"A: Ist das eine Tatsache oder eine Meinung?\nB: Das ist eine Tatsache. Es gibt Beweise.\nA: Tatsache ist, dass die Zahlen stimmen.\nB: Gut. Auf Tatsachen kann man sich verlassen.",exampleSrc:"A: Is that a fact or an opinion?\nB: That is a fact. There is evidence.\nA: The fact is that the numbers are correct.\nB: Good. You can rely on facts.",funFact:"Tat (deed/act) + Sache (thing). A 'deed-thing,' something that actually happened. Harder than 'Fakt.' 'Tatsache ist, dass...' (The fact is that...) opens many journalistic sentences. A Tatsache cannot be argued away."},
{type:"fb",s:"Ist das eine {1} oder nur eine Meinung? Es gibt Beweise.",a:["Tatsache"],opts:["Stellungnahme","Tatsache","Medienlandschaft","Transparenz"],hint:"The noun for something that actually happened, a proven fact. Tat (deed) + Sache (thing).",sSrc:"Is that a fact or just an opinion? There is evidence."},
{type:"teach",trg:"die Transparenz",src:"transparency",pos:"noun",gender:"f",note:"Feminine noun. From Latin transparere (to show through).\nThe opposite of Verschleierung (veiling).",example:"A: Wir fordern mehr Transparenz.\nB: Ja, Transparenz ist wichtig für Vertrauen.\nA: Ohne Transparenz gibt es keine Glaubwürdigkeit.\nB: Die Medien müssen transparent arbeiten.",exampleSrc:"A: We demand more transparency.\nB: Yes, transparency is important for trust.\nA: Without transparency there is no credibility.\nB: The media must work transparently.",funFact:"From Latin 'transparere' (to show through). Seeing through institutional walls. The opposite of Verschleierung (veiling). 'Mehr Transparenz fordern' (to demand more transparency) is a rallying cry in media criticism and politics alike."},
{type:"teach",trg:"der Wahrheitsgehalt",src:"truth content, veracity",pos:"noun",gender:"m",note:"Masculine noun. Wahrheit (truth) + Gehalt (content).\nNot 'true or false' but 'how much truth?'",example:"A: Wie hoch ist der Wahrheitsgehalt dieses Artikels?\nB: Der Wahrheitsgehalt ist fragwürdig.\nA: Man muss den Wahrheitsgehalt immer überprüfen.\nB: Das ist die Basis jeder Medienkompetenz.",exampleSrc:"A: How high is the truth content of this article?\nB: The truth content is questionable.\nA: One must always verify the truth content.\nB: That is the basis of all media literacy.",funFact:"Wahrheit (truth) + Gehalt (content). Not a binary 'true or false' but 'how much truth does this contain?' A nuanced concept. 'Den Wahrheitsgehalt überprüfen' (to verify the truth content) treats information as a spectrum, not a switch."},
{type:"teach",trg:"die Objektivitaet",src:"objectivity",pos:"noun",gender:"f",note:"Feminine noun. From objektiv + -itaet.\nThe ideal of reporting without bias.",example:"A: Gibt es absolute Objektivitaet im Journalismus?\nB: Nein, aber man kann sich ihr annähern.\nA: Objektivitaet bleibt das Ziel.\nB: Genau. Jeder Journalist strebt nach Objektivitaet.",exampleSrc:"A: Is there absolute objectivity in journalism?\nB: No, but you can approach it.\nA: Objectivity remains the goal.\nB: Exactly. Every journalist strives for objectivity.",funFact:"From objektiv + -itaet. Nominalisierung: adjective 'objektiv' becomes noun 'Objektivitaet.' The ideal of reporting without bias. Perfect Objektivitaet may be impossible, but striving for it separates journalism from propaganda."},
{type:"teach",trg:"hinterfragen",src:"to question critically",pos:"verb",gender:null,note:"Not separable. Hinter (behind) + fragen (to ask).\nAsking what is behind the surface.",example:"A: Wir müssen diese Darstellung hinterfragen.\nB: Ja, man sollte alles hinterfragen.\nA: Wer hinterfragt, findet die Wahrheit.\nB: Hinterfragen ist die wichtigste Faehigkeit.",exampleSrc:"A: We must critically question this portrayal.\nB: Yes, one should question everything critically.\nA: Those who question find the truth.\nB: Critical questioning is the most important skill.",funFact:"Hinter (behind) + fragen (to ask). Not separable. Asking what is behind the surface. The verb of Medienkompetenz. 'Nachrichten hinterfragen' (to question news critically) means going deeper than headlines."},
{type:"teach",trg:"einschätzen",src:"to assess, to evaluate",pos:"verb",gender:null,note:"Separable: ein + schätzen. Ich schätze es ein.\nMaking your internal estimate.",example:"A: Wie schätzen Sie die Lage ein?\nB: Ich schätze die Situation als kritisch ein.\nA: Kann man das zuverlässiig einschätzen?\nB: Nur mit guter Recherche.",exampleSrc:"A: How do you assess the situation?\nB: I assess the situation as critical.\nA: Can one reliably assess that?\nB: Only with good research.",funFact:"Ein (in) + schätzen (to estimate/value). Separable. Making your internal estimate. 'Wie schätzen Sie das ein?' (How do you assess this?) is a standard question in German interviews and discussions. Your Einschätzung (assessment) reveals your expertise."},
{type:"teach",trg:"widersprechen",src:"to contradict",pos:"verb",gender:null,note:"Not separable. Wider (against) + sprechen (to speak).\nTakes Dativ: Ich widerspreche Ihnen.",example:"A: Ich muss Ihnen widersprechen.\nB: Warum widersprechen Sie mir?\nA: Weil die Fakten Ihrer Darstellung widersprechen.\nB: Dann zeigen Sie mir die Fakten.",exampleSrc:"A: I must contradict you.\nB: Why do you contradict me?\nA: Because the facts contradict your portrayal.\nB: Then show me the facts.",funFact:"Wider (against) + sprechen (to speak). Not separable. Speaking against. Takes Dativ: 'Ich widerspreche Ihnen' (I contradict you). In German debate culture, widersprechen is expected and respected. Silence implies agreement."},
{type:"teach",trg:"infrage stellen",src:"to call into question",pos:"verb",gender:null,note:"Two-word phrase. In Frage (into question) + stellen (to place).\nMore formal than bezweifeln (to doubt).",example:"A: Darf man die Ergebnisse infrage stellen?\nB: Natürlich. Alles darf man infrage stellen.\nA: Die Studie wird von Experten infrage gestellt.\nB: Das ist ein gutes Zeichen: Wissenschaft lebt vom Hinterfragen.",exampleSrc:"A: May one call the results into question?\nB: Of course. Everything may be called into question.\nA: The study is being called into question by experts.\nB: That is a good sign: science thrives on questioning.",funFact:"In Frage (into question) + stellen (to place). Placing something into the realm of question. More formal than 'bezweifeln' (to doubt). 'Die Glaubwürdigkeit infrage stellen' (to call credibility into question) is a powerful move in media criticism."},
{type:"teach",trg:"überprüfen",src:"to verify, to check",pos:"verb",gender:null,note:"Not separable. Über (over) + prüfen (to test).\nGoing over something carefully to test its truth.",example:"A: Hast du die Fakten überprüft?\nB: Ja, ich habe alles überprüft.\nA: Informationen muss man immer überprüfen.\nB: Ohne Überprüfung gibt es keine Glaubwürdigkeit.",exampleSrc:"A: Did you verify the facts?\nB: Yes, I verified everything.\nA: Information must always be verified.\nB: Without verification there is no credibility.",funFact:"Über (over) + prüfen (to test). Not separable. Going over something carefully to test its truth. The Faktencheck verb. 'Informationen überprüfen' (to verify information) is the journalist's daily bread."},
{type:"mc",q:"Die Fakten Ihrer Darstellung widersprechen der Wahrheit. Was bedeutet 'widersprechen'?",opts:["Grundsaetzlich zustimmen und bestaetigen","Etwas veröffentlichen und weiter verbreiten","Gegen etwas sprechen, dagegen argumentieren","Etwas direkt infrage stellen und hinterfragen"],ans:"Gegen etwas sprechen, dagegen argumentieren",hint:"The inseparable prefix 'wider' means against. Opposing a statement or person with words."},

{type:"fb",s:"Was ist der {1} dieser Entscheidung?",a:["Hintergrund"],opts:["Hintergrund","Vordergrund","Standpunkt","Gegenstand"],hint:"The context or circumstances behind something. The part you do not see at first glance.",sSrc:"What is the background of this decision?"}
]},
{id:"deu_r26l5b",title:"Die andere Seite (Teil 2)",icon:"\uD83D\uDDE3\uFE0F",xp:15,board:true,steps:[
{type:"intro",title:"Die andere Seite (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"übertreiben",src:"to exaggerate",pos:"verb",gender:null,note:"Not separable. Über (over) + treiben (to drive).\nDriving something beyond the limit.",example:"A: Die Boulevardpresse übertreibt immer.\nB: Ja, sie übertreiben masslos.\nA: Man darf nicht übertreiben, wenn man serioes berichten will.\nB: Übertreibung zerstoert Glaubwürdigkeit.",exampleSrc:"A: The tabloid press always exaggerates.\nB: Yes, they exaggerate excessively.\nA: One must not exaggerate when reporting seriously.\nB: Exaggeration destroys credibility.",funFact:"Über (over) + treiben (to drive). Not separable. Driving something over the limit. 'Masslos übertreiben' (to exaggerate excessively). Übertreibung (exaggeration) is the tabloid's primary tool and the quality newspaper's greatest enemy."},
{type:"teach",trg:"faktenbasiert",src:"fact-based",pos:"adj",gender:null,note:"Fakten (facts) + basiert (based).\nThe gold standard of journalism.",example:"A: Ist dieser Bericht faktenbasiert?\nB: Ja, alles ist faktenbasiert und belegt.\nA: Faktenbasierte Berichterstattung ist selten.\nB: Aber sie ist das Wichtigste im Journalismus.",exampleSrc:"A: Is this report fact-based?\nB: Yes, everything is fact-based and documented.\nA: Fact-based reporting is rare.\nB: But it is the most important thing in journalism.",funFact:"Fakten (facts) + basiert (based). The gold standard of journalism. If it is not faktenbasiert, it is opinion. 'Faktenbasierte Berichterstattung' (fact-based reporting) separates serious media from propaganda and Meinungsmache."},
{type:"teach",trg:"oberflächlich",src:"superficial",pos:"adj",gender:null,note:"Oberfläche (surface) + -lich.\nOnly touching the surface. The opposite of gründlich.",example:"A: Die Analyse ist leider oberflächlich.\nB: Ja, sie geht nicht in die Tiefe.\nA: Oberflächliche Berichterstattung hilft niemandem.\nB: Man muss tiefer graben.",exampleSrc:"A: The analysis is unfortunately superficial.\nB: Yes, it does not go in depth.\nA: Superficial reporting helps nobody.\nB: One must dig deeper.",funFact:"Oberfläche (surface) + -lich. Only touching the surface. A damning criticism in German academia and journalism. The opposite of 'gründlich' (thorough). When a German calls your work 'oberflächlich,' it stings."},
{type:"teach",trg:"zweifelhaft",src:"doubtful, dubious",pos:"adj",gender:null,note:"Zweifel (doubt) + -haft.\nFull of doubt. Not proven wrong, but suspicious.",example:"A: Die Quelle ist zweifelhaft.\nB: Warum ist sie zweifelhaft?\nA: Weil keine Belege angegeben werden.\nB: Zweifelhafte Quellen sollte man meiden.",exampleSrc:"A: The source is dubious.\nB: Why is it dubious?\nA: Because no evidence is given.\nB: One should avoid dubious sources.",funFact:"Zweifel (doubt) + -haft. Full of doubt. When something is zweifelhaft, you should not trust it. Not proven wrong, but suspicious enough to deserve scrutiny. 'Zweifelhafte Methoden' (questionable methods) is a serious accusation."},
{type:"teach",trg:"unzuverlässiig",src:"unreliable",pos:"adj",gender:null,note:"Un- + zuverlässiig (reliable).\nThe worst label a source can get.",example:"A: Dieser Journalist ist unzuverlässiig.\nB: Warum ist er unzuverlässiig?\nA: Er hat schon dreimal falsche Informationen verbreitet.\nB: Dann ist er als Quelle unzuverlässiig.",exampleSrc:"A: This journalist is unreliable.\nB: Why is he unreliable?\nA: He has spread false information three times already.\nB: Then he is unreliable as a source.",funFact:"Un- + zuverlässiig (reliable). The negation of zuverlässiig. In journalism, the worst label a source can get. Once a source is deemed unzuverlässiig, no serious journalist will cite them again."},
{type:"fb",s:"Wir müssen diese Darstellung {1}, um die Wahrheit zu finden.",a:["hinterfragen"],opts:["widersprechen","übertreiben","einschätzen","hinterfragen"],hint:"The verb that means to question critically, to look behind the surface. Hinter + fragen.",sSrc:"We must critically question this portrayal in order to find the truth."},
{type:"teach",trg:"vertrauenswürdig",src:"trustworthy",pos:"adj",gender:null,note:"Vertrauen (trust) + würdig (worthy).\nWorthy of your trust. The highest media compliment.",example:"A: Ist diese Zeitung vertrauenswürdig?\nB: Ja, sie gilt als sehr vertrauenswürdig.\nA: Vertrauenswürdige Medien sind wichtig für die Demokratie.\nB: Ohne Vertrauen funktioniert Journalismus nicht.",exampleSrc:"A: Is this newspaper trustworthy?\nB: Yes, it is considered very trustworthy.\nA: Trustworthy media are important for democracy.\nB: Without trust, journalism does not work.",funFact:"Vertrauen (trust) + würdig (worthy). Worthy of your Vertrauen. The highest compliment for a journalist or medium. 'Vertrauenswürdige Medien' are the backbone of any functioning democracy."},
{type:"teach",trg:"unparteiisch",src:"impartial",pos:"adj",gender:null,note:"Un- + parteiisch (partisan).\nNot taking any Partei (side). The journalistic ideal.",example:"A: Sollten Journalisten unparteiisch sein?\nB: Ja, in Berichten müssen sie unparteiisch sein.\nA: Unparteiische Berichterstattung ist das Ziel.\nB: In Kommentaren darf man Partei ergreifen.",exampleSrc:"A: Should journalists be impartial?\nB: Yes, in reports they must be impartial.\nA: Impartial reporting is the goal.\nB: In commentaries, one may take sides.",funFact:"Un- + parteiisch (partisan). Not taking any Partei (side). The judicial and journalistic ideal. Berichte must be unparteiisch. Kommentare may take sides. Knowing the difference is Medienkompetenz."},
{type:"mc",q:"Während die recherchierten Fakten sich leicht überprüfen lassen, ist die oberflächliche Darstellung fragwürdig. Welche drei Konstrukte kommen vor?",opts:["Adversativsatz + Partizipialattribut + Passiversatz","Nur ein einziger einfacher Adversativsatz","Adversativsatz zusammen mit dem Partizipialattribut allein","Nur der Passiversatz ganz allein"],ans:"Adversativsatz + Partizipialattribut + Passiversatz",hint:"Three constructs: the contrast connector, the compressed pre-noun modifier (Partizip II before the noun), and the 'sich lassen' passive alternative."},
{type:"fb",s:"{1} der Korrespondent ausführlich berichtet, übertreibt die Boulevardpresse.",a:["Während"],opts:["Weil","Während","Obwohl","Damit"],hint:"The connector for contrasting two media practices. 'Whereas' in the adversative sense.",sSrc:"While the correspondent reports in detail, the tabloid press exaggerates."},
{type:"drag_fill",s:"Die Glaubwürdigkeit {1} sich anhand der Quellen {2}.",blanks:{"1":"lässt","2":"überprüfen"},pool:["lässt","überprüfen","lassen","überprüft","wird","geprüft"],hint:"The 'sich lassen' + Infinitiv pattern: 'Glaubwürdigkeit kann anhand der Quellen überprüft werden.'"},
{type:"mc",q:"Was bedeutet 'zweifelhaft'?",opts:["to exaggerate","transparency","to assess, to evaluate","doubtful, dubious"],ans:"doubtful, dubious",hint:"Zweifel (doubt) + -haft (-like). Having the quality of doubt about it."},
{type:"fb",s:"Dieser Journalist ist {1}.",a:["unzuverlässiig"],opts:["die Objektivitaet","unzuverlässiig","vertrauenswürdig","die Tatsache"],hint:"Un- (not) + zuverlassig (reliable). The prefix negates trustworthiness.",sSrc:"This journalist is unreliable."},
{type:"mc",q:"Was bedeutet 'vertrauenswürdig'?",opts:["trustworthy","objectivity","unreliable","statement, position paper"],ans:"trustworthy",hint:"Vertrauen (trust) + wurdig (worthy). Deserving of someone's confidence."}
]},
{id:"deu_r26l6",title:"Faktencheck",icon:"\uD83D\uDD0D",xp:15,board:true,steps:[
{type:"intro",title:"Faktencheck",desc:"Verumius reads the newspaper with fewer red marks. Learn newspaper sections, media formats, and practice all three grammar constructs in media context.",goals:["Learn vocabulary for newspaper sections and media formats","Practice all three grammar constructs in media contexts","Learn to verify information"]},
{type:"story",speaker:"narrator",mood:"quiet",art:"de-ber-apartment-evening",trg:"Später Nachmittag. Verumius kommt nach Hause. Auf dem Küchentisch liegt die heutige Ausgabe der Zeit. Daneben: sein roter Stift. Es ist fast ein Ritual geworden.",src:"Late afternoon. Verumius comes home. On the kitchen table lies today's edition of Die Zeit. Next to it: his red pen. It has almost become a ritual."},
{type:"story",speaker:"narrator",mood:"satisfied",trg:"Abend. Verumius' Wohnung. Die Zeit liegt auf dem Tisch. Weniger rote Markierungen als gestern. Er liest das Feuilleton. Er versteht die Glosse. Er lacht sogar über die Karikatur.",src:"Evening. Verumius's apartment. Die Zeit lies on the table. Fewer red marks than yesterday. He reads the arts section. He understands the satirical piece. He even laughs at the political cartoon."},
{type:"story",speaker:"verumius",mood:"happy",trg:"Gestern waren es dreissig rote Markierungen pro Seite. Heute sind es zehn. In einer Woche vielleicht fünf. Fortschritt ist messbar.",src:"Yesterday there were thirty red marks per page. Today there are ten. In a week perhaps five. Progress is measurable."},
{type:"story",speaker:"narrator",mood:"warm",trg:"Das Radio kündigt an: 'Sie hoerten den Deutschlandfunk. Es folgt der Kommentar.' Verumius hoert zu. Er versteht. Nicht jedes Wort, aber das Argument. Das genügt.",src:"The radio announces: 'You have been listening to Deutschlandfunk. The commentary follows.' Verumius listens. He understands. Not every word, but the argument. That is enough."},
{type:"teach",trg:"das Feuilleton",src:"arts and culture section",pos:"noun",gender:"n",note:"Neuter noun. From French feuillet (little leaf/page).\nPronounced 'foy-ye-TONG.'",example:"A: Liest du das Feuilleton?\nB: Ja, das Feuilleton ist mein Lieblingsteil der Zeitung.\nA: Was steht heute im Feuilleton?\nB: Eine Rezension und ein Essay über moderne Kunst.",exampleSrc:"A: Do you read the arts section?\nB: Yes, the arts section is my favorite part of the newspaper.\nA: What is in the arts section today?\nB: A review and an essay about modern art.",funFact:"From French 'feuillet' (little leaf/page). Book reviews, theater criticism, cultural essays. Germany's Feuilleton tradition is legendary. The FAZ Feuilleton is considered one of the most influential in the German-speaking world."},
{type:"teach",trg:"die Glosse",src:"satirical commentary",pos:"noun",gender:"f",note:"Feminine noun. From Greek glossa (tongue/language).\nShort, witty, biting. Humor with a point.",example:"A: Hast du die Glosse gelesen?\nB: Ja, die Glosse war sehr witzig.\nA: Der Autor schreibt jede Woche eine Glosse.\nB: Seine Glossen sind immer treffend.",exampleSrc:"A: Did you read the satirical piece?\nB: Yes, the satirical piece was very witty.\nA: The author writes a satirical piece every week.\nB: His satirical pieces are always spot-on.",funFact:"From Greek 'glossa' (tongue/language). Short, witty, biting. 'Eine Glosse schreiben' (to write a satirical piece). The journalist's sharpest weapon: humor with a point. A good Glosse makes you laugh and think at the same time."},
{type:"teach",trg:"die Karikatur",src:"political cartoon, caricature",pos:"noun",gender:"f",note:"Feminine noun. From Italian caricatura (exaggeration).\nSatire protected by Kunstfreiheit.",example:"A: Die Karikatur auf der Meinungsseite ist genial.\nB: Ja, die Karikatur trifft den Punkt.\nA: Karikaturen sagen mehr als tausend Worte.\nB: Deshalb sind sie so wirkungsvoll.",exampleSrc:"A: The cartoon on the opinion page is brilliant.\nB: Yes, the cartoon hits the mark.\nA: Cartoons say more than a thousand words.\nB: That is why they are so effective.",funFact:"From Italian 'caricatura' (exaggeration). German newspapers feature Karikaturen on their opinion pages. Satire is protected under German law as Kunstfreiheit (artistic freedom). A Karikatur can say what words cannot."},
{type:"mc",q:"Die Glosse im Feuilleton war sehr witzig. Was ist eine Glosse?",opts:["Ein kurzer satirischer Kommentar mit Pointe","Ein ausführlicher investigativer Bericht","Eine Nachrichtensendung im Fernsehen","Eine wissenschaftliche Fachzeitschrift"],ans:"Ein kurzer satirischer Kommentar mit Pointe",hint:"A short, biting piece of writing in the arts section. Humor with a sharp point."},
{type:"teach",trg:"der Leserbrief",src:"letter to the editor",pos:"noun",gender:"m",note:"Masculine noun. Leser (reader) + Brief (letter).\nThe reader's voice in print.",example:"A: Hast du einen Leserbrief geschrieben?\nB: Ja, mein Leserbrief wurde veröffentlicht.\nA: Worüber war der Leserbrief?\nB: Über die einseitige Berichterstattung letzte Woche.",exampleSrc:"A: Did you write a letter to the editor?\nB: Yes, my letter to the editor was published.\nA: What was the letter about?\nB: About the one-sided reporting last week.",funFact:"Leser (reader) + Brief (letter). The reader's voice. German newspapers still publish Leserbriefe prominently. 'Einen Leserbrief schreiben' (to write a letter to the editor) is an act of civic engagement."},
{type:"teach",trg:"die Bildunterschrift",src:"photo caption",pos:"noun",gender:"f",note:"Feminine noun. Bild (picture) + Unterschrift (caption).\nThe text underneath a photograph.",example:"A: Lies die Bildunterschrift.\nB: Die Bildunterschrift erklärt das Foto.\nA: Ohne Bildunterschrift versteht man den Kontext nicht.\nB: Stimmt, die Bildunterschrift liefert wichtige Details.",exampleSrc:"A: Read the photo caption.\nB: The photo caption explains the photograph.\nA: Without a photo caption, you do not understand the context.\nB: True, the photo caption provides important details.",funFact:"Bild (picture) + Unterschrift (caption/signature). The text underneath a photograph. Unter (under) + Schrift (writing). Often overlooked but essential for context. A misleading Bildunterschrift can change the meaning of an entire photo."},
{type:"fb",s:"Die {1} unter dem Foto erklärt den Kontext des Bildes.",a:["Bildunterschrift"],opts:["Überschrift","Bildunterschrift","Schlagzeile","Quellenangabe"],hint:"The compound noun for the text that appears underneath a photograph. Bild + Unterschrift.",sSrc:"The photo caption under the photograph explains the context of the image."},
{type:"teach",trg:"die Überschrift",src:"headline, title",pos:"noun",gender:"f",note:"Feminine noun. Über (over) + Schrift (writing).\nBroader than Schlagzeile: every article has one.",example:"A: Die Überschrift klingt reisserisch.\nB: Ja, die Überschrift übertreibt.\nA: Lies immer zuerst die Überschrift.\nB: Aber vertraue ihr nicht blind.",exampleSrc:"A: The headline sounds sensationalist.\nB: Yes, the headline exaggerates.\nA: Always read the headline first.\nB: But do not trust it blindly.",funFact:"Über (over) + Schrift (writing). The writing OVER the text. Broader than Schlagzeile: every article has an Überschrift, but only front-page news has a Schlagzeile. The Überschrift sets expectations."},
{type:"teach",trg:"die Titelseite",src:"front page",pos:"noun",gender:"f",note:"Feminine noun. Titel (title) + Seite (page).\nThe most valuable real estate in print journalism.",example:"A: Was steht auf der Titelseite?\nB: Ein Skandal. Immer ein Skandal.\nA: Auf der Titelseite zu stehen ist eine grosse Sache.\nB: Ja, die Titelseite bestimmt die öffentliche Debatte.",exampleSrc:"A: What is on the front page?\nB: A scandal. Always a scandal.\nA: Being on the front page is a big deal.\nB: Yes, the front page determines the public debate.",funFact:"Titel (title) + Seite (page). The most valuable real estate in print journalism. 'Auf der Titelseite stehen' (to be on the front page). What makes it to the Titelseite shapes the national conversation."},
{type:"teach",trg:"die Quellenangabe",src:"source citation",pos:"noun",gender:"f",note:"Feminine noun. Quelle (source) + Angabe (indication).\nJournalism without it is rumor.",example:"A: Wo ist die Quellenangabe?\nB: Der Artikel hat keine Quellenangabe.\nA: Ohne Quellenangabe ist der Bericht nicht glaubwürdig.\nB: Genau. Quellenangaben sind Pflicht.",exampleSrc:"A: Where is the source citation?\nB: The article has no source citation.\nA: Without a source citation, the report is not credible.\nB: Exactly. Source citations are mandatory.",funFact:"Quelle (source) + Angabe (indication). Journalism without Quellenangabe is rumor. Academic writing without it is plagiarism. 'Ohne Quellenangabe' (without citing sources) is one of the harshest criticisms in German media and academia."},
{type:"teach",trg:"der Schreibstil",src:"writing style",pos:"noun",gender:"m",note:"Masculine noun. Schreib (writing) + Stil (style).\nEvery journalist develops their own.",example:"A: Der Schreibstil ist sehr klar.\nB: Ja, ein guter Schreibstil macht den Unterschied.\nA: Sachlich, pointiert oder literarisch?\nB: Der Schreibstil haengt von der Textsorte ab.",exampleSrc:"A: The writing style is very clear.\nB: Yes, a good writing style makes the difference.\nA: Factual, pointed, or literary?\nB: The writing style depends on the text type.",funFact:"Schreib (writing) + Stil (style). Every journalist develops their own. Sachlich, pointiert, oder literarisch. The Schreibstil is the fingerprint. 'Ein klarer Schreibstil' (a clear writing style) is the hallmark of great journalism."},
{type:"teach",trg:"der Faktencheck",src:"fact check",pos:"noun",gender:"m",note:"Masculine noun. Fakten (facts) + Check.\nGerman media organizations like Correctiv specialize in this.",example:"A: Hast du einen Faktencheck gemacht?\nB: Ja, der Faktencheck hat die Behauptung widerlegt.\nA: Jede Nachricht verdient einen Faktencheck.\nB: Correctiv macht das professionell.",exampleSrc:"A: Did you do a fact check?\nB: Yes, the fact check disproved the claim.\nA: Every piece of news deserves a fact check.\nB: Correctiv does this professionally.",funFact:"Fakten (facts) + Check. Borrowed from English. 'Einen Faktencheck durchführen' (to conduct a fact check). German media organizations like Correctiv specialize in Faktenchecks. In the age of Desinformation, the Faktencheck is essential."},
{type:"mc",q:"Was macht ein Faktencheck?",opts:["Er schreibt ausführliche Leitartikel","Er moderiert eine tägliche Sendung","Er prüft, ob Behauptungen stimmen","Er veröffentlicht regelmäßige Rezensionen"],ans:"Er prüft, ob Behauptungen stimmen",hint:"The purpose of a fact check is to verify whether claims are true. Think about what 'Fakten' and 'Check' mean together."}
]},
{id:"deu_r26l6b",title:"Faktencheck (Teil 2)",icon:"\uD83D\uDD0D",xp:15,board:true,steps:[
{type:"intro",title:"Faktencheck (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"moderieren",src:"to moderate, to host",pos:"verb",gender:null,note:"From Latin moderare (to regulate).\nThe Moderator guides without expressing opinion.",example:"A: Wer moderiert die Sendung?\nB: Frau Mueller moderiert heute Abend.\nA: Sie moderiert immer sehr professionell.\nB: Ja, eine gute Moderatorin bleibt unparteiisch.",exampleSrc:"A: Who is hosting the show?\nB: Ms. Mueller is hosting tonight.\nA: She always hosts very professionally.\nB: Yes, a good host remains impartial.",funFact:"From Latin 'moderare' (to regulate). The Moderator/Moderatorin guides the discussion without expressing their own opinion. 'Eine Sendung moderieren' (to host a show). German talk shows are moderated, not just hosted."},
{type:"teach",trg:"rezensieren",src:"to review (critically)",pos:"verb",gender:null,note:"From Rezension. Regular verb.\nWriting a critical evaluation of art or literature.",example:"A: Hast du das Buch rezensiert?\nB: Ja, ich habe es für das Feuilleton rezensiert.\nA: Wie rezensiert man fair?\nB: Man lobt Stärken und benennt Schwaechen.",exampleSrc:"A: Did you review the book?\nB: Yes, I reviewed it for the arts section.\nA: How does one review fairly?\nB: One praises strengths and names weaknesses.",funFact:"From Rezension. Verbalisierung: Rezension (noun) becomes rezensieren (verb). Writing a critical evaluation of art or literature. Found in the Feuilleton of every serious German newspaper."},
{type:"teach",trg:"ausstrahlen",src:"to broadcast, to air",pos:"verb",gender:null,note:"Separable: aus + strahlen (to radiate).\nRadiation of information outward.",example:"A: Wann wird die Sendung ausgestrahlt?\nB: Sie wird um zwanzig Uhr ausgestrahlt.\nA: Die ARD strahlt die Nachrichten täglich aus.\nB: Ja, die Tagesschau wird seit 1952 ausgestrahlt.",exampleSrc:"A: When will the show be broadcast?\nB: It will be broadcast at eight PM.\nA: ARD broadcasts the news daily.\nB: Yes, the Tagesschau has been broadcast since 1952.",funFact:"Aus (out) + strahlen (to radiate/beam). Separable. Radio and TV stations strahlen their programs aus. Radiation of information. 'Die Sendung wird um 20 Uhr ausgestrahlt' is the standard broadcast announcement."},
{type:"teach",trg:"senden",src:"to send, to broadcast",pos:"verb",gender:null,note:"From Old German sendan. The basic media verb.\nDer Sender (broadcaster), die Sendung (broadcast).",example:"A: Wir senden live aus Berlin.\nB: Der Sender sendet rund um die Uhr.\nA: Was senden sie gerade?\nB: Einen Bericht über die Pressekonferenz.",exampleSrc:"A: We are broadcasting live from Berlin.\nB: The broadcaster transmits around the clock.\nA: What are they broadcasting right now?\nB: A report about the press conference.",funFact:"From Old German 'sendan.' The basic verb. 'Der Sender' (the broadcaster), 'die Sendung' (the broadcast). One root builds an entire media vocabulary. 'Live senden' (to broadcast live) is the purest form of journalism."},
{type:"teach",trg:"streamen",src:"to stream",pos:"verb",gender:null,note:"Borrowed from English. Fully integrated into German.\nDer Streamingdienst = streaming service.",example:"A: Kann man die Sendung auch streamen?\nB: Ja, man kann sie in der Mediathek streamen.\nA: Ich streame lieber als live zu schauen.\nB: Das machen heute die meisten.",exampleSrc:"A: Can one also stream the show?\nB: Yes, you can stream it in the media library.\nA: I prefer to stream rather than watch live.\nB: Most people do that today.",funFact:"Borrowed from English 'to stream.' Fully integrated into German. 'Der Streamingdienst' (streaming service). Netflix, Spotify, Podcasts: all streamen. ARD and ZDF have their own Mediathek for on-demand streaming."},
{type:"teach",trg:"veröffentlichen",src:"to publish, to make public",pos:"verb",gender:null,note:"Not separable. Ver- + öffentlich (public) + -en.\nMaking something public.",example:"A: Wann wird der Artikel veröffentlicht?\nB: Er wird morgen veröffentlicht.\nA: Der Verlag hat das Buch letzte Woche veröffentlicht.\nB: Ja, die Veröffentlichung war ein Erfolg.",exampleSrc:"A: When will the article be published?\nB: It will be published tomorrow.\nA: The publisher published the book last week.\nB: Yes, the publication was a success.",funFact:"Ver- + öffentlich (public) + -en. Verbalisierung: öffentlich (adjective) becomes veröffentlichen (verb). Making something public. 'Einen Artikel veröffentlichen' (to publish an article) is the final step in journalism."},
{type:"teach",trg:"meinungsbildend",src:"opinion-forming",pos:"adj",gender:null,note:"Meinung (opinion) + bildend (forming).\nPartizip I as adjective. Media that shape thought.",example:"A: Die FAZ ist ein meinungsbildendes Medium.\nB: Ja, meinungsbildende Medien tragen grosse Verantwortung.\nA: Wer meinungsbildend ist, hat Macht.\nB: Und Macht braucht Kontrolle.",exampleSrc:"A: The FAZ is an opinion-forming medium.\nB: Yes, opinion-forming media bear great responsibility.\nA: Those who form opinions have power.\nB: And power needs oversight.",funFact:"Meinung (opinion) + bildend (forming). A Partizip I used as adjective. Media that actively shape how people think. 'Meinungsbildende Medien' carry great responsibility. Power with responsibility."},
{type:"teach",trg:"medial",src:"media-related",pos:"adj",gender:null,note:"From Medium/Medien. The adjective form.\nMediale Aufmerksamkeit = media attention.",example:"A: Das Thema hat mediale Aufmerksamkeit bekommen.\nB: Ja, der mediale Druck ist enorm.\nA: Mediale Praesenz ist heute wichtig.\nB: Wer medial nicht existiert, existiert nicht.",exampleSrc:"A: The topic received media attention.\nB: Yes, the media pressure is enormous.\nA: Media presence is important today.\nB: Those who do not exist in media do not exist.",funFact:"From Medium/Medien. The adjective form. 'Mediale Aufmerksamkeit' (media attention). 'Medial praesent sein' (to have media presence). In the modern world, medial visibility determines relevance."},
{type:"teach",trg:"transparent",src:"transparent",pos:"adj",gender:null,note:"From Latin transparere (to show through).\nThe opposite of verschleiern.",example:"A: Die Berichterstattung muss transparent sein.\nB: Ja, transparente Methoden schaffen Vertrauen.\nA: Je transparenter, desto glaubwürdiger.\nB: Transparenz ist kein Luxus, sondern Pflicht.",exampleSrc:"A: Reporting must be transparent.\nB: Yes, transparent methods build trust.\nA: The more transparent, the more credible.\nB: Transparency is not a luxury but a duty.",funFact:"From Latin 'transparere' (to show through). Making your methods and sources visible. The opposite of verschleiern (to veil). 'Transparente Berichterstattung' (transparent reporting) is the modern journalistic standard."},
{type:"teach",trg:"zeitgemaess",src:"contemporary, up-to-date",pos:"adj",gender:null,note:"Zeit (time) + gemaess (in accordance with).\nIn accordance with the times.",example:"A: Ist Printjournalismus noch zeitgemaess?\nB: Print allein ist nicht mehr zeitgemaess.\nA: Zeitgemaesser Journalismus ist multimedial.\nB: Online, Podcast, Video: alles zusammen.",exampleSrc:"A: Is print journalism still contemporary?\nB: Print alone is no longer contemporary.\nA: Contemporary journalism is multimedia.\nB: Online, podcast, video: all together.",funFact:"Zeit (time) + gemaess (in accordance with). Media must evolve. Print alone is no longer zeitgemaess. 'Zeitgemaesser Journalismus' (contemporary journalism) combines print, online, podcast, and video."},
{type:"mc",q:"Während die zu prüfenden Fakten sich leicht verifizieren lassen, bleibt die irreführende Überschrift problematisch. Wie viele Grammatikkonstrukte kommen vor?",opts:["Drei: Adversativsatz + Partizipialattribut + Passiversatz","Zwei: ein Adversativsatz kombiniert mit dem Passiversatz","Eins: nur ein einziger einfacher Adversativsatz","Zwei: Partizipialattribut zusammen mit einem Adversativsatz"],ans:"Drei: Adversativsatz + Partizipialattribut + Passiversatz",hint:"Three constructs: the contrast connector, a gerundive pre-noun modifier (zu + Partizip I before the noun), and the 'sich lassen' passive alternative."},
{type:"fb",s:"Der Verlag hat den Artikel gestern {1}.",a:["veröffentlicht"],opts:["öffentlich","veröffentlicht","veröffentlichen","Veröffentlichung"],hint:"The Partizip II of the verb meaning 'to make public'. It belongs to the Perfekt construction here.",sSrc:"The publisher published the article yesterday."},
{type:"drag_fill",s:"Der {1} in der Tageszeitung hat einen klaren {2}.",blanks:{"1":"Leitartikel","2":"Schreibstil"},pool:["Leitartikel","Schreibstil","Leserbrief","Faktencheck","Kommentar","Sendung"],hint:"The lead article in a daily newspaper has a clear writing style. Two compound nouns."},
{type:"match",pairs:[{trg:"Feuilleton",src:"arts and culture section"},{trg:"Glosse",src:"satirical commentary"},{trg:"Karikatur",src:"political cartoon"},{trg:"Leserbrief",src:"letter to the editor"}]},
{type:"mc",q:"Was bedeutet 'moderieren'?",opts:["to moderate, to host","front page","political cartoon, caricature","to stream"],ans:"to moderate, to host",hint:"Near-identical in English. Latin: moderare (to regulate, to guide)."},
{type:"fb",s:"Wie sagt man 'to review (critically)' auf Deutsch? {1}",a:["rezensieren"],opts:["rezensieren","der Schreibstil","das Feuilleton","zeitgemaess"],hint:"From Rezension (review). To write a critical assessment of a creative work.",sSrc:"How do you say 'to review (critically)' in German?"},
{type:"mc",q:"Was bedeutet 'ausstrahlen'?",opts:["photo caption","to publish, to make public","writing style","to broadcast, to air"],ans:"to broadcast, to air",hint:"Aus- (out) + strahlen (to beam). To beam a signal outward to viewers."},
{type:"fb",s:"Wir {1} live aus Berlin.",a:["senden"],opts:["streamen","rezensieren","die Titelseite","senden"],hint:"Related to English 'send.' To transmit content over radio or television.",sSrc:"We are broadcasting live from Berlin."},
{type:"mc",q:"Was bedeutet 'streamen'?",opts:["to stream","headline, title","fact check","arts and culture section"],ans:"to stream",hint:"English loanword. Digital media delivered continuously in real time."},
{type:"fb",s:"Die FAZ ist ein {1}es Medium.",a:["meinungsbildend"],opts:["senden","die Quellenangabe","meinungsbildend","die Titelseite"],hint:"Meinung (opinion) + bildend (forming). Shaping what the public thinks.",sSrc:"The FAZ is an opinion-forming medium."},
{type:"mc",q:"Was bedeutet 'medial'?",opts:["to stream","media-related","to review (critically)","satirical commentary"],ans:"media-related",hint:"From Latin medius (middle) + -al. Concerning channels of communication."},
{type:"fb",s:"Die Berichterstattung muss {1} sein.",a:["transparent"],opts:["rezensieren","transparent","ausstrahlen","moderieren"],hint:"Near-identical in English. Open and visible to public scrutiny.",sSrc:"Reporting must be transparent."},
{type:"mc",q:"Was bedeutet 'zeitgemaess'?",opts:["front page","contemporary, up-to-date","to publish, to make public","arts and culture section"],ans:"contemporary, up-to-date",hint:"Zeit (time) + gemass (according to). Fitting the spirit of the current era."}
]},
{id:"deu_r26l7",title:"Zwischen den Zeilen",icon:"\uD83D\uDCCB",xp:15,board:true,steps:[
{type:"intro",title:"Zwischen den Zeilen",desc:"Test everything from Unit 26. Prove you can critically analyze media and use Partizipialattribute, passive alternatives, and adversative clauses.",goals:["Test everything from Unit 26","Analyze media critically","Use Partizipialattribute, passive alternatives, and adversative clauses"]},
{type:"story",speaker:"narrator",mood:"matter-of-fact",art:"de-ber-office-lunch",trg:"Mittagspause. Verumius sitzt mit Mia und zwei Kollegen in der Kantine. Ein Artikel über Medienkompetenz liegt zwischen den Tabletts. Mia tippt darauf.",src:"Lunch break. Verumius sits with Mia and two colleagues in the canteen. An article about media literacy lies between the trays. Mia taps on it."},
{type:"story",speaker:"mia",mood:"challenging",art:"de-ber-office-lunch",trg:"Okay, Faktencheck. Wer findet die meisten Partizipialattribute in diesem Artikel? Der berichtende Journalist, die zu prüfenden Fakten, die veröffentlichten Ergebnisse. Wer kann sie alle entschlüsseln?",src:"Okay, fact check. Who can find the most Partizipialattribute in this article? The reporting journalist, the facts to be examined, the published results. Who can decode them all?"},
{type:"story",speaker:"verumius",mood:"amused",art:"de-ber-office-lunch",trg:"Vor zwei Wochen hätte ich kein einziges erkannt. Jetzt sehe ich sie überall. In jeder Schlagzeile, in jedem Kommentar. Man kann sie nicht mehr übersehen.",src:"Two weeks ago I would not have recognized a single one. Now I see them everywhere. In every headline, in every commentary. You cannot unsee them."},
{type:"teach",trg:"der Chefredakteur",src:"editor-in-chief",pos:"noun",gender:"m",note:"Masculine noun. Chef (boss) + Redakteur (editor).\nFinal say on what gets published.",example:"A: Wer ist der Chefredakteur?\nB: Der Chefredakteur ist Herr Schmidt.\nA: Der Chefredakteur entscheidet, was veröffentlicht wird.\nB: Ja, er hat das letzte Wort.",exampleSrc:"A: Who is the editor-in-chief?\nB: The editor-in-chief is Mr. Schmidt.\nA: The editor-in-chief decides what gets published.\nB: Yes, he has the last word.",funFact:"Chef (boss) + Redakteur (editor). The person with final say on what gets published. 'Die Chefredakteurin' is the feminine form. The most powerful position in a newsroom. One person, immense responsibility."},
{type:"teach",trg:"der Berichterstatter",src:"reporter",pos:"noun",gender:"m",note:"Masculine noun. Bericht (report) + Erstatter (renderer).\nThe person who creates the Bericht.",example:"A: Unser Berichterstatter ist vor Ort.\nB: Der Berichterstatter berichtet live.\nA: Ein guter Berichterstatter bleibt sachlich.\nB: Ja, Fakten zuerst, Meinung später.",exampleSrc:"A: Our reporter is on the scene.\nB: The reporter reports live.\nA: A good reporter stays factual.\nB: Yes, facts first, opinion later.",funFact:"Bericht (report) + Erstatter (renderer). The person who creates the Bericht. 'Unser Berichterstatter vor Ort' (our reporter on the scene). On location, in the action, delivering the story."},
{type:"teach",trg:"der Rezipient",src:"media consumer, recipient",pos:"noun",gender:"m",note:"Masculine noun. From Latin recipere (to receive).\nN-Deklination. Der muendige Rezipient.",example:"A: Wer ist der Rezipient einer Nachricht?\nB: Der Rezipient ist die Person, die die Nachricht empfängt.\nA: Ein muendiger Rezipient hinterfragt.\nB: Genau. Nicht einfach alles glauben.",exampleSrc:"A: Who is the recipient of a message?\nB: The recipient is the person who receives the message.\nA: An informed recipient questions critically.\nB: Exactly. Do not simply believe everything.",funFact:"From Latin 'recipere' (to receive). The person who receives the message. N-Deklination: Rezipient, Rezipienten. 'Der muendige Rezipient' (the informed consumer) can distinguish fact from opinion."},
{type:"mc",q:"In der Kommunikationstheorie: Der Sender schickt eine Nachricht an den Rezipienten. Was ist ein Rezipient?",opts:["Der Chefredakteur einer grossen Zeitung","Die Person, die eine Nachricht empfängt","Der Autor eines wichtigen Leitartikels","Der Moderator einer Nachrichtensendung"],ans:"Die Person, die eine Nachricht empfängt",hint:"From Latin 'recipere' (to receive). The one at the receiving end of a media message."},
{type:"teach",trg:"die Nachrichtensprecherin",src:"newsreader (female)",pos:"noun",gender:"f",note:"Feminine noun. Nachrichten + Sprecherin (female speaker).\nThe voice and face of the Tagesschau.",example:"A: Wer ist die Nachrichtensprecherin heute?\nB: Frau Weber ist die Nachrichtensprecherin.\nA: Die Nachrichtensprecherin liest die Nachrichten vor.\nB: Ja, seit über zehn Jahren.",exampleSrc:"A: Who is the newsreader today?\nB: Ms. Weber is the newsreader.\nA: The newsreader reads the news.\nB: Yes, for over ten years.",funFact:"Nachrichten + Sprecherin (female speaker). The voice and face of the Tagesschau. 'Die Nachrichtensprecher/in liest die Nachrichten vor.' Reading news to the nation. In Germany, Nachrichtensprecher are trusted public figures."},
{type:"teach",trg:"der Übersetzer",src:"translator",pos:"noun",gender:"m",note:"Masculine noun. Über (across) + Setzer (one who sets).\n'Setting across' meaning from one language to another.",example:"A: Verumius war einmal Übersetzer.\nB: Wirklich? Für welche Sprachen?\nA: Englisch und Niederlaendisch.\nB: Und jetzt übersetzt er sich selbst ins Deutsche.",exampleSrc:"A: Verumius was once a translator.\nB: Really? For which languages?\nA: English and Dutch.\nB: And now he translates himself into German.",funFact:"Über (over/across) + Setzer (one who sets). Someone who 'sets across' meaning from one language to another. Verumius was once an Übersetzer. Now he IS the translation."},
{type:"teach",trg:"die Übersetzerin",src:"translator (female)",pos:"noun",gender:"f",note:"Feminine noun. Übersetzer + -in.\nLiteraturübersetzerin = literary translator.",example:"A: Die Übersetzerin hat den Roman ins Deutsche übersetzt.\nB: Ist die Übersetzerin bekannt?\nA: Ja, sie ist eine preisgekroente Literaturübersetzerin.\nB: Gute Übersetzerinnen sind Gold wert.",exampleSrc:"A: The translator translated the novel into German.\nB: Is the translator well known?\nA: Yes, she is an award-winning literary translator.\nB: Good translators are worth their weight in gold.",funFact:"Übersetzer + -in. The standard feminine form. 'Literaturübersetzerin' (literary translator) is a respected profession in Germany. Great translators make world literature accessible."},
{type:"teach",trg:"die Sondersendung",src:"special broadcast",pos:"noun",gender:"f",note:"Feminine noun. Sonder (special) + Sendung (broadcast).\nBreaking news interrupts regular programming.",example:"A: Wir unterbrechen für eine Sondersendung.\nB: Was ist passiert?\nA: Die Sondersendung berichtet über den Vorfall.\nB: Sondersendungen bedeuten immer etwas Wichtiges.",exampleSrc:"A: We interrupt for a special broadcast.\nB: What happened?\nA: The special broadcast reports on the incident.\nB: Special broadcasts always mean something important.",funFact:"Sonder (special) + Sendung (broadcast). Breaking news interrupts regular programming. 'Wir unterbrechen für eine Sondersendung' (We interrupt for a special broadcast) is a sentence that makes every viewer pay attention."},
{type:"teach",trg:"das Online-Medium",src:"online medium",pos:"noun",gender:"n",note:"Neuter noun. Online + Medium.\nPlural: Online-Medien. The digital transformation.",example:"A: Liest du Online-Medien?\nB: Ja, ich lese hauptsaechlich Online-Medien.\nA: Welches Online-Medium empfiehlst du?\nB: Spiegel Online und Zeit Online sind gut.",exampleSrc:"A: Do you read online media?\nB: Yes, I mainly read online media.\nA: Which online medium do you recommend?\nB: Spiegel Online and Zeit Online are good.",funFact:"Online + Medium. Plural: Online-Medien. Spiegel Online, Zeit Online, tagesschau.de. The digital transformation of German journalism. Print newspapers are declining, Online-Medien are rising."},
{type:"fb",s:"Wir unterbrechen für eine {1} zum Thema Klimapolitik.",a:["Sondersendung"],opts:["Sondersendung","Tageszeitung","Druckerei","Quellenangabe"],hint:"A special broadcast that interrupts regular programming for important breaking news.",sSrc:"We interrupt for a special broadcast about climate policy."}
]},
{id:"deu_r26l7b",title:"Zwischen den Zeilen (Teil 2)",icon:"\uD83D\uDCCB",xp:15,board:true,steps:[
{type:"intro",title:"Zwischen den Zeilen (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"das Printmedium",src:"print medium",pos:"noun",gender:"n",note:"Neuter noun. Print + Medium.\nPlural: Printmedien. The ongoing crisis of print.",example:"A: Haben Printmedien noch eine Zukunft?\nB: Printmedien verlieren Auflage.\nA: Aber das Printmedium hat noch Vorteile.\nB: Ja, Tiefe und Glaubwürdigkeit.",exampleSrc:"A: Do print media still have a future?\nB: Print media are losing circulation.\nA: But the print medium still has advantages.\nB: Yes, depth and credibility.",funFact:"Print + Medium. Plural: Printmedien. Newspapers, magazines, books. 'Printmedien verlieren Auflage' (Print media are losing circulation). The ongoing crisis. Yet print still carries an aura of Serioesitaet."},
{type:"teach",trg:"die Qualitaetszeitung",src:"quality newspaper",pos:"noun",gender:"f",note:"Feminine noun. Qualitaet + Zeitung.\nContrasts with Boulevardzeitung (tabloid).",example:"A: Die FAZ ist eine Qualitaetszeitung.\nB: Ja, Qualitaetszeitungen recherchieren gründlich.\nA: Qualitaetszeitungen kosten mehr.\nB: Aber die Qualitaet rechtfertigt den Preis.",exampleSrc:"A: The FAZ is a quality newspaper.\nB: Yes, quality newspapers research thoroughly.\nA: Quality newspapers cost more.\nB: But the quality justifies the price.",funFact:"Qualitaet + Zeitung. FAZ, Sueddeutsche Zeitung, Die Zeit. Contrasts with Boulevardzeitung (tabloid). In-depth reporting, fact-based, analytical. The backbone of German public discourse."},
{type:"teach",trg:"öffentlich machen",src:"to make public, to disclose",pos:"verb",gender:null,note:"Verbal phrase. Öffentlich (public) + machen (to make).\nLess formal than veröffentlichen.",example:"A: Sollen wir die Ergebnisse öffentlich machen?\nB: Ja, die Bürger haben ein Recht auf Information.\nA: Wann machen wir es öffentlich?\nB: Sobald der Faktencheck abgeschlossen ist.",exampleSrc:"A: Should we make the results public?\nB: Yes, citizens have a right to information.\nA: When do we make it public?\nB: As soon as the fact check is completed.",funFact:"Öffentlich (public) + machen (to make). The verbal phrase form of veröffentlichen. Less formal, more conversational. 'Informationen öffentlich machen' (to make information public) is the democratic principle of Transparenz in action."},
{type:"teach",trg:"ausblenden",src:"to fade out, to ignore",pos:"verb",gender:null,note:"Separable: aus + blenden (to blind/blend).\nChoosing not to see something.",example:"A: Man darf Kritik nicht ausblenden.\nB: Stimmt, wer Kritik ausblendet, lernt nicht.\nA: Die Medien blenden unbequeme Wahrheiten aus.\nB: Das ist das Gegenteil von Transparenz.",exampleSrc:"A: One must not ignore criticism.\nB: True, those who ignore criticism do not learn.\nA: The media fade out uncomfortable truths.\nB: That is the opposite of transparency.",funFact:"Aus (out) + blenden (to blind/blend). Separable. Originally a film term (fade to black). Now: choosing not to see something. 'Kritik ausblenden' (to ignore criticism) is a dangerous habit for any journalist or institution."},
{type:"teach",trg:"verdraengen",src:"to suppress, to displace",pos:"verb",gender:null,note:"Not separable. Ver- + draengen (to push).\nPushing something from consciousness.",example:"A: Man kann die Wahrheit nicht ewig verdraengen.\nB: Nein, verdraengte Wahrheiten kommen zurück.\nA: Die Gesellschaft verdraengt unbequeme Themen.\nB: Aber Verdraengung loest keine Probleme.",exampleSrc:"A: You cannot suppress the truth forever.\nB: No, suppressed truths come back.\nA: Society suppresses uncomfortable topics.\nB: But suppression does not solve problems.",funFact:"Ver- + draengen (to push). Not separable. Pushing something away from consciousness. Psychological and social. 'Unangenehme Wahrheiten verdraengen' (to suppress uncomfortable truths). What you verdraengen does not disappear. It grows."},
{type:"teach",trg:"verleumden",src:"to slander, to defame",pos:"verb",gender:null,note:"Not separable. Ver- + Leumund (reputation).\nA criminal offense in Germany.",example:"A: Der Journalist wurde verleumdet.\nB: Wer hat ihn verleumdet?\nA: Ein Politiker hat ihn öffentlich verleumdet.\nB: Verleumdung ist strafbar. Er kann klagen.",exampleSrc:"A: The journalist was slandered.\nB: Who slandered him?\nA: A politician slandered him publicly.\nB: Slander is punishable. He can sue.",funFact:"Ver- + Leumund (reputation). Attacking someone's reputation. A criminal offense in Germany: Verleumdung carries fines or prison. 'Einen Journalisten verleumden' (to slander a journalist) is an attack on press freedom itself."},
{type:"teach",trg:"verharmlosen",src:"to trivialize, to downplay",pos:"verb",gender:null,note:"Not separable. Ver- + harmlos (harmless).\nMaking something seem harmless when it is not.",example:"A: Man darf die Gefahr nicht verharmlosen.\nB: Stimmt, Verharmlosung ist gefaehrlich.\nA: Die Medien verharmlosen das Problem.\nB: Das führt dazu, dass niemand handelt.",exampleSrc:"A: One must not trivialize the danger.\nB: True, trivialization is dangerous.\nA: The media trivialize the problem.\nB: That leads to nobody taking action.",funFact:"Ver- + harmlos (harmless). Verbalisierung: harmlos becomes verharmlosen. Making something seem harmlos when it is not. 'Die Gefahr verharmlosen' (to trivialize the danger) is a common media criticism. Verharmlosung can have deadly consequences."},
{type:"teach",trg:"zensieren",src:"to censor",pos:"verb",gender:null,note:"From Zensur. What authoritarian regimes do.\nWhat democracies prohibit.",example:"A: In Deutschland darf man die Presse nicht zensieren.\nB: Richtig, Zensur ist verfassungswidrig.\nA: Manche Laender zensieren das Internet.\nB: Das Grundgesetz schützt uns davor.",exampleSrc:"A: In Germany, you may not censor the press.\nB: Correct, censorship is unconstitutional.\nA: Some countries censor the internet.\nB: The Basic Law protects us from that.",funFact:"From Zensur. Verbalisierung: Zensur (noun) becomes zensieren (verb). What authoritarian regimes do. What democracies prohibit. 'Die Presse zensieren' (to censor the press) violates Article 5 of the German Grundgesetz."},
{type:"teach",trg:"skandaloes",src:"scandalous",pos:"adj",gender:null,note:"From Skandal + -oes.\nSo shocking it becomes a Skandal.",example:"A: Die Enthuellungen sind skandaloes.\nB: Ja, die skandaloesen Details schockieren.\nA: Skandaloese Nachrichten verkaufen sich gut.\nB: Aber nicht alles Skandaloese ist auch wichtig.",exampleSrc:"A: The revelations are scandalous.\nB: Yes, the scandalous details shock.\nA: Scandalous news sells well.\nB: But not everything scandalous is also important.",funFact:"From Skandal (scandal) + -oes. The adjective of Skandal. When something is so shocking it becomes a Skandal. 'Skandaloese Enthuellung' (scandalous revelation). The tabloid press thrives on the Skandaloese."},
{type:"teach",trg:"subjektiv",src:"subjective",pos:"adj",gender:null,note:"From Latin subjectivus.\nThe opposite of objektiv. Personal perspective.",example:"A: Ist dieser Kommentar objektiv?\nB: Nein, er ist bewusst subjektiv.\nA: Subjektive Meinungen gehören in den Kommentar.\nB: Ja, aber nicht in den Bericht.",exampleSrc:"A: Is this commentary objective?\nB: No, it is deliberately subjective.\nA: Subjective opinions belong in the commentary.\nB: Yes, but not in the report.",funFact:"From Latin 'subjectivus.' The opposite of objektiv. Personal perspective. In journalism: subjektiv is acceptable in Kommentare, not in Berichte. Knowing where subjectivity belongs is part of Medienkompetenz."},
{type:"teach",trg:"wahrheitsgemaess",src:"truthful, in accordance with truth",pos:"adj",gender:null,note:"Wahrheit (truth) + gemaess (in accordance).\nThe legal standard for journalism.",example:"A: Journalisten müssen wahrheitsgemaess berichten.\nB: Ja, das ist ihre gesetzliche Pflicht.\nA: Wahrheitsgemaesse Berichterstattung schützt die Demokratie.\nB: Ohne sie gibt es kein Vertrauen.",exampleSrc:"A: Journalists must report truthfully.\nB: Yes, that is their legal duty.\nA: Truthful reporting protects democracy.\nB: Without it there is no trust.",funFact:"Wahrheit (truth) + gemaess (in accordance with). The legal standard. Journalists must report wahrheitsgemaess or face consequences. 'Wahrheitsgemaess berichten' (to report truthfully) is the foundation of all credible journalism."},
{type:"teach",trg:"zuverlässiig",src:"reliable",pos:"adj",gender:null,note:"Zu (to) + verlaessig (relying).\nThe most important quality of information.",example:"A: Ist diese Quelle zuverlässiig?\nB: Ja, sie ist absolut zuverlässiig.\nA: Zuverlässiige Informationen sind die Basis.\nB: Ohne Zuverlässiigkeit gibt es kein Vertrauen.",exampleSrc:"A: Is this source reliable?\nB: Yes, it is absolutely reliable.\nA: Reliable information is the foundation.\nB: Without reliability there is no trust.",funFact:"Zu (to) + verlaessig (relying). Sources you can rely on. The most important quality of information. A zuverlässiige Quelle is a journalist's most valuable asset. Without Zuverlässiigkeit, everything collapses."},
{type:"mc",q:"Die von unabhängigen Journalisten recherchierten Fakten sind leicht zu überprüfen. Welche Konstrukte kommen vor?",opts:["Erweitertes Partizipialattribut + Passiversatz","Nur das einfache Partizipialattribut","Nur der Passiversatz allein","Adversativsatz und Passiversatz kombiniert hier"],ans:"Erweitertes Partizipialattribut + Passiversatz",hint:"'Die von ... recherchierten Fakten': an extended pre-noun modifier with an agent phrase. 'Sind leicht zu überprüfen': a sein + zu passive alternative."},
{type:"fb",s:"{1} die Qualitaetszeitung recherchiert, kopiert die Boulevardpresse nur Agenturmeldungen.",a:["Während"],opts:["Während","Weil","Obwohl","Damit"],hint:"The adversative connector for contrasting two media practices. 'Whereas' one does X, the other does Y.",sSrc:"While the quality newspaper researches, the tabloid press only copies agency reports."},
{type:"mc",q:"Welche drei Saetze drücken dieselbe Bedeutung mit verschiedenen Passiversatz-Formen aus?",opts:["Das wird erklärt / Das ist erklärt / Das hat man erklärt","Das lässt sich erklären / Das wurde erklärt / Das erklärt sich worden","Das lässt sich erklären / Das ist zu erklären / Das ist erklärbar","Das ist erklärbar / Das war erklärbar / Das wird erklärbar"],ans:"Das lässt sich erklären / Das ist zu erklären / Das ist erklärbar",hint:"Three alternative constructions for expressing ability-passive without werden: a reflexive, a sein-zu, and an adjective form."},
{type:"drag_fill",s:"{1} die zu {2} Nachricht serioes klingt, ist der Wahrheitsgehalt fragwürdig.",blanks:{"1":"Obwohl","2":"prüfende"},pool:["Obwohl","prüfende","Während","geprüft","Weil","prüfenden"],hint:"A concessive subordinating conjunction opens the clause. The pre-noun modifier uses zu + Partizip I (gerundive) to describe something that needs verifying."},
{type:"match",pairs:[{trg:"Chefredakteur",src:"editor-in-chief"},{trg:"Berichterstatter",src:"reporter"},{trg:"Rezipient",src:"media consumer"},{trg:"Korrespondent",src:"correspondent"}]},
{type:"mc",q:"Ein Artikel ohne Quellenangabe, mit reisserischer Überschrift und einseitiger Darstellung ist am ehesten...",opts:["serioes und faktenbasiert","boulevardesk und fragwürdig","investigativ und gründlich","unparteiisch und ausgewogen"],ans:"boulevardesk und fragwürdig",hint:"No sources, sensationalist headline, one-sided. These are the hallmarks of tabloid journalism."},
{type:"mc",q:"Was bedeutet 'das Printmedium'?",opts:["to suppress, to displace","subjective","translator","print medium"],ans:"print medium",hint:"An English loanword combined with the German noun for a channel of communication. Newspapers and magazines on paper."},
{type:"fb",s:"Sollen wir die Ergebnisse {1}?",a:["öffentlich machen"],opts:["ausblenden","wahrheitsgemaess","der Rezipient","öffentlich machen"],hint:"Öffentlich (public) + a common auxiliary verb. To release information to everyone.",sSrc:"Should we make the results public?"},
{type:"mc",q:"Was bedeutet 'ausblenden'?",opts:["to fade out, to ignore","to suppress, to displace","media consumer, recipient","scandalous"],ans:"to fade out, to ignore",hint:"Aus- (out) + blenden (to blind). To deliberately look away from something."},
{type:"fb",s:"Man kann die Wahrheit nicht ewig {1}.",a:["verdraengen"],opts:["die Nachrichtensprecherin","die Sondersendung","skandaloes","verdraengen"],hint:"Ver- + drangen (to push). To push uncomfortable truths from your mind.",sSrc:"You cannot suppress the truth forever."},
{type:"mc",q:"Was bedeutet 'verleumden'?",opts:["to slander, to defame","to trivialize, to downplay","online medium","reporter"],ans:"to slander, to defame",hint:"Ver- + Leumund (reputation). To destroy someone's good name with lies."},
{type:"fb",s:"Man darf die Gefahr nicht {1}.",a:["verharmlosen"],opts:["verharmlosen","zuverlässiig","die Sondersendung","verleumden"],hint:"Ver- + harmlos (harmless). To make a real danger seem harmless.",sSrc:"One must not trivialize the danger."},
{type:"mc",q:"Was bedeutet 'zensieren'?",opts:["reporter","to make public, to disclose","to censor","editor-in-chief"],ans:"to censor",hint:"Sounds like its English equivalent. Latin: censere (to assess and suppress)."},
{type:"fb",s:"Die Enthuellungen sind {1}.",a:["skandaloes"],opts:["wahrheitsgemaess","skandaloes","der Chefredakteur","öffentlich machen"],hint:"Cognate of English 'scandalous.' Greek: skandalon (stumbling block).",sSrc:"The revelations are scandalous."},
{type:"mc",q:"Was bedeutet 'subjektiv'?",opts:["media consumer, recipient","print medium","reporter","subjective"],ans:"subjective",hint:"Latin: sub + iacere (to throw under). Based on personal opinion, not facts."},
{type:"fb",s:"Journalisten müssen {1} berichten.",a:["wahrheitsgemaess"],opts:["der Übersetzer","wahrheitsgemaess","verharmlosen","öffentlich machen"],hint:"Wahrheit (truth) + gemass (in accordance with). Reporting that follows truth.",sSrc:"Journalists must report truthfully."},
{type:"mc",q:"Was bedeutet 'zuverlässiig'?",opts:["reliable","to slander, to defame","to censor","subjective"],ans:"reliable",hint:"Zu- + verlassen (to rely on) + -ig. A source you can fully depend on."}
]},
{id:"deu_r26l8",title:"Medienkompetenz",icon:"\uD83C\uDF93",xp:15,board:true,steps:[
{type:"intro",title:"Medienkompetenz",desc:"Reflect on media literacy. Review all constructs from Unit 26. Understand the participial system through familiar V1 words. Celebrate your progress.",goals:["Reflect on media literacy","Review all Unit 26 constructs","Understand participles through V1 words","Celebrate your progress"]},
{type:"story",speaker:"narrator",mood:"satisfied",trg:"Abend. Verumius' Wohnung. Die Zeit auf dem Tisch. Weniger rote Markierungen. Er liest das Feuilleton, ohne zu stocken. Er versteht die Glosse. Er streitet mit dem Leitartikel in seinem Kopf.",src:"Evening. Verumius's apartment. Die Zeit on the table. Fewer red marks. He reads the arts section without stopping. He understands the satirical piece. He argues with the editorial in his head."},
{type:"story",speaker:"verumius",mood:"happy",trg:"Letzte Woche konnte ich die Schlagzeilen kaum verstehen. Heute diskutiere ich über Medienkompetenz. Hätte mir das vor einem Jahr jemand gesagt, hätte ich gelacht.",src:"Last week I could barely understand the headlines. Today I discuss media literacy. If someone had told me that a year ago, I would have laughed."},
{type:"story",speaker:"narrator",mood:"warm",trg:"Sein Handy vibriert. Mia: 'Hast du den Kommentar in der FAZ gelesen? Wir müssen morgen drüber reden.'",src:"His phone buzzes. Mia: 'Did you read the commentary in the FAZ? We need to talk about it tomorrow.'"},
{type:"story",speaker:"verumius",mood:"confident",trg:"Er öffnet die FAZ-App. Er liest. Er hat eine Meinung. Er wird sie morgen teilen.",src:"He opens the FAZ app. He reads. He has an opinion. He will share it tomorrow."},
{type:"teach",trg:"die Auflage",src:"circulation, print run",pos:"noun",gender:"f",note:"Feminine noun. Auf (on) + Lage (layer/edition).\nHow many copies a newspaper prints.",example:"A: Wie hoch ist die Auflage der Bild-Zeitung?\nB: Die Auflage liegt bei über einer Million.\nA: Die Auflage sinkt seit Jahren.\nB: Ja, digitale Abonnements ersetzen den Druck.",exampleSrc:"A: What is the circulation of the Bild newspaper?\nB: The circulation is over one million.\nA: Circulation has been declining for years.\nB: Yes, digital subscriptions are replacing print.",funFact:"Auf (on) + Lage (layer/edition). How many copies a newspaper prints. 'Eine Auflage von 500.000' (a circulation of 500,000). Digital subscriptions are changing what Auflage means. Print declines, digital grows."},
{type:"teach",trg:"die Boulevardpresse",src:"tabloid press",pos:"noun",gender:"f",note:"Feminine noun. Boulevard + Presse.\nBild is Germany's biggest Boulevardzeitung.",example:"A: Die Boulevardpresse übertreibt wieder.\nB: Ja, die Boulevardpresse lebt von Skandalen.\nA: Kann man der Boulevardpresse vertrauen?\nB: Nur mit Vorsicht. Immer gegenchecken.",exampleSrc:"A: The tabloid press is exaggerating again.\nB: Yes, the tabloid press lives off scandals.\nA: Can you trust the tabloid press?\nB: Only with caution. Always cross-check.",funFact:"Boulevard + Presse. Named after the French boulevards where newspapers were sold. Die Boulevardpresse prioritizes sensation over substance. Bild is Germany's largest Boulevardzeitung and a constant subject of media criticism."},
{type:"teach",trg:"die Druckerei",src:"printing press, print shop",pos:"noun",gender:"f",note:"Feminine noun. Druck (print) + -erei (place of).\nThe -erei suffix marks a place of business.",example:"A: In welcher Druckerei wird die Zeitung gedruckt?\nB: In einer grossen Druckerei in Hamburg.\nA: Braucht man noch Druckereien?\nB: Ja, Printmedien werden noch in Druckereien produziert.",exampleSrc:"A: In which print shop is the newspaper printed?\nB: In a large print shop in Hamburg.\nA: Are print shops still needed?\nB: Yes, print media are still produced in print shops.",funFact:"Druck (print/pressure) + -erei (place where). Where newspapers physically become paper. The -erei suffix marks a place of business: Baeckerei, Metzgerei, Druckerei. A disappearing world as digital media grows."},
{type:"teach",trg:"die Einflussnahme",src:"exerting influence",pos:"noun",gender:"f",note:"Feminine noun. Einfluss (influence) + Nahme (taking).\nStronger than beeinflussen.",example:"A: Gibt es politische Einflussnahme auf die Medien?\nB: Ja, Einflussnahme ist ein ständiges Problem.\nA: Wie erkennt man Einflussnahme?\nB: Wenn bestimmte Themen systematisch fehlen.",exampleSrc:"A: Is there political influence on the media?\nB: Yes, exerting influence is a constant problem.\nA: How do you recognize it?\nB: When certain topics are systematically absent.",funFact:"Einfluss (influence) + Nahme (taking). When someone actively takes influence. Stronger than beeinflussen. 'Politische Einflussnahme auf Medien' (political influence on media) threatens journalistic independence."},
{type:"teach",trg:"der Empfaenger",src:"receiver, recipient",pos:"noun",gender:"m",note:"Masculine noun. Empfangen (to receive) + -er.\nCommunication: Sender > Nachricht > Empfaenger.",example:"A: Wer ist der Empfaenger dieser Nachricht?\nB: Der Empfaenger ist die Öffentlichkeit.\nA: Der Empfaenger entscheidet, was er glaubt.\nB: Deshalb braucht der Empfaenger Medienkompetenz.",exampleSrc:"A: Who is the recipient of this message?\nB: The recipient is the public.\nA: The recipient decides what to believe.\nB: That is why the recipient needs media literacy.",funFact:"Empfangen (to receive) + -er. Communication theory: Sender > Nachricht > Empfaenger. You are the Empfaenger of media. A muendiger Empfaenger (informed recipient) does not passively consume but actively evaluates."},
{type:"fb",s:"In der Kommunikation sendet der Sender eine Nachricht an den {1}.",a:["Empfaenger"],opts:["Empfaenger","Rezipient","Redakteur","Korrespondent"],hint:"The noun for the person who receives a message. Sender and ... form a pair in communication theory.",sSrc:"In communication, the sender sends a message to the receiver."},
{type:"teach",trg:"die Fachzeitschrift",src:"specialized journal",pos:"noun",gender:"f",note:"Feminine noun. Fach (subject) + Zeitschrift (magazine).\nFor experts, not the general public.",example:"A: In welcher Fachzeitschrift wurde die Studie veröffentlicht?\nB: In einer medizinischen Fachzeitschrift.\nA: Fachzeitschriften sind zuverlässiiger als Boulevardpresse.\nB: Ja, sie haben strenge Qualitaetskontrollen.",exampleSrc:"A: In which journal was the study published?\nB: In a medical journal.\nA: Specialized journals are more reliable than tabloids.\nB: Yes, they have strict quality controls.",funFact:"Fach (subject) + Zeitschrift (magazine). For experts, not the general public. The opposite of Boulevardpresse. 'Eine medizinische Fachzeitschrift' (a medical journal) undergoes peer review. Reliability over Reichweite."},
{type:"teach",trg:"die Informationsflut",src:"information overload",pos:"noun",gender:"f",note:"Feminine noun. Information + Flut (flood).\nToo much information, too little time.",example:"A: Wie geht man mit der Informationsflut um?\nB: Man muss filtern und priorisieren.\nA: Die Informationsflut überfordert viele Menschen.\nB: Medienkompetenz hilft gegen die Informationsflut.",exampleSrc:"A: How do you deal with information overload?\nB: You must filter and prioritize.\nA: Information overload overwhelms many people.\nB: Media literacy helps against information overload.",funFact:"Information + Flut (flood). Too much information, too little time. 'In der Informationsflut untergehen' (to drown in the information flood). The modern media challenge. Medienkompetenz is the lifejacket."},
{type:"teach",trg:"die Meinungsmache",src:"opinion manipulation",pos:"noun",gender:"f",note:"Feminine noun. Meinung (opinion) + Mache (making).\nDeliberately shaping public opinion.",example:"A: Ist das Journalismus oder Meinungsmache?\nB: Das ist eindeutig Meinungsmache.\nA: Meinungsmache ist das Gegenteil von Journalismus.\nB: Ja, Journalismus informiert, Meinungsmache manipuliert.",exampleSrc:"A: Is that journalism or opinion manipulation?\nB: That is clearly opinion manipulation.\nA: Opinion manipulation is the opposite of journalism.\nB: Yes, journalism informs, opinion manipulation manipulates.",funFact:"Meinung (opinion) + Mache (making). Deliberately shaping public opinion through biased content. Negative connotation. When media 'makes' opinions instead of informing, that is Meinungsmache. The enemy of Objektivitaet."},
{type:"teach",trg:"das Rechercheergebnis",src:"research finding",pos:"noun",gender:"n",note:"Neuter noun. Recherche + Ergebnis (result).\nWhat the journalist found after investigating.",example:"A: Was sind die Rechercheergebnisse?\nB: Die Rechercheergebnisse bestätigen den Verdacht.\nA: Ohne Rechercheergebnis gibt es keinen Artikel.\nB: Genau. Fakten zuerst.",exampleSrc:"A: What are the research findings?\nB: The research findings confirm the suspicion.\nA: Without research findings there is no article.\nB: Exactly. Facts first.",funFact:"Recherche + Ergebnis (result). What the journalist found after investigating. The basis for the Bericht. Without Rechercheergebnisse, a Bericht is just Meinungsmache."},
{type:"teach",trg:"die sozialen Medien",src:"social media",pos:"noun",gender:"f",note:"Always plural. Sozial (social) + Medien (media).\nFacebook, Instagram, TikTok, X.",example:"A: Nutzt du soziale Medien?\nB: Ja, aber ich hinterfrage alles, was ich dort lese.\nA: Soziale Medien verändern die Medienlandschaft.\nB: Ja, jeder kann dort veröffentlichen.",exampleSrc:"A: Do you use social media?\nB: Yes, but I critically question everything I read there.\nA: Social media is changing the media landscape.\nB: Yes, anyone can publish there.",funFact:"Sozial (social) + Medien (media). Always plural. Facebook, Instagram, TikTok, X. 'Soziale Medien verändern die Medienlandschaft' (Social media is changing the media landscape). Everyone is now a Sender and an Empfaenger."},
{type:"mc",q:"Die Boulevardpresse lebt von Skandalen. Was ist das Gegenteil der Boulevardpresse?",opts:["Die Qualitaetszeitung","Die Fachzeitschrift","Die Druckerei","Die Einflussnahme"],ans:"Die Qualitaetszeitung",hint:"The opposite of tabloid press is a newspaper known for thorough research and factual reporting."},
{type:"teach",trg:"die Verbreitung",src:"dissemination, spread",pos:"noun",gender:"f",note:"Feminine noun. From verbreiten (to spread).\nNominalisierung of verbreiten.",example:"A: Die Verbreitung von Falschinformationen ist ein Problem.\nB: Ja, die schnelle Verbreitung macht es gefaehrlich.\nA: Soziale Medien beschleunigen die Verbreitung.\nB: Deshalb ist Medienkompetenz so wichtig.",exampleSrc:"A: The spread of misinformation is a problem.\nB: Yes, the rapid spread makes it dangerous.\nA: Social media accelerate the spread.\nB: That is why media literacy is so important.",funFact:"From verbreiten (to spread). Nominalisierung. 'Die Verbreitung von Falschinformationen' (the spread of misinformation). How information travels. In the digital age, Verbreitung happens in seconds."},
{type:"teach",trg:"die Verleumdung",src:"slander, defamation",pos:"noun",gender:"f",note:"Feminine noun. From verleumden (to slander).\nA criminal offense under German law.",example:"A: Das ist Verleumdung!\nB: Ja, Verleumdung ist strafbar.\nA: Kann man gegen Verleumdung klagen?\nB: Ja, das deutsche Recht schützt vor Verleumdung.",exampleSrc:"A: That is slander!\nB: Yes, slander is punishable.\nA: Can you sue for slander?\nB: Yes, German law protects against slander.",funFact:"From verleumden (to slander). Nominalisierung of verleumden. 'Verleumdung ist strafbar' (Slander is punishable). A criminal offense under German law. Reputation has legal protection in Germany."},
{type:"tip",title:"Partizipialattribute mit bekannten Wörtern: V1 trifft V2",text:"You already know these participles from earlier units:\nlachend (laughing), spielend (playing), schlafend (sleeping), wachsend (growing), fahrend (travelling), gelesen (read), geschrieben (written), geöffnet (opened), gekocht (cooked), gebrochen (broken).\n\nNow as Partizipialattribute:\ndas lachende Kind (the laughing child)\nder geschriebene Brief (the written letter)\ndie wachsende Kritik (the growing criticism)\ndas geöffnete Fenster (the opened window)\n\nPartizip I (lachend, wachsend) = active, ongoing.\nPartizip II (geschrieben, geöffnet) = passive, completed.\n\nThe same system that works for media words works for all German nouns."},
{type:"mc",q:"Der geschriebene Artikel wurde veröffentlicht. Was ist 'der geschriebene Artikel'?",opts:["Ein gew\u00f6hnliches attributives Adjektiv ohne Partizip","Ein normaler Passivsatz mit werden","Eine Konjunktiv-II-Form f\u00fcr irreale S\u00e4tze","Partizipialattribut: der Artikel, der geschrieben wurde"],ans:"Partizipialattribut: der Artikel, der geschrieben wurde",hint:"A Partizip II is placed before the noun as a modifier. Ask yourself: what is the noun doing, or what was done to it?"},
{type:"mc",q:"Mia schreibt: 'Hast du den FAZ-Kommentar gelesen?' Verumius antwortet: 'Während die recherchierten Fakten sich belegen lassen, ist die Darstellung fragwürdig.' Welches Register verwendet Verumius?",opts:["Umgangssprachlich mit einfachen Alltagsverben","Gemischtes Register mit deutlichen Grammatikfehlern","Poetisch mit Vergleichen, Metaphern und Bildern","Akademisch/formell mit komplexen Konstruktionen"],ans:"Akademisch/formell mit komplexen Konstruktionen",hint:"Verumius uses three advanced constructs in one sentence. That is professional German, not casual chat."},
{type:"teach",trg:"nachvollziehbar",src:"comprehensible, traceable, understandable",pos:"adj",gender:null,note:"Nach (after) + vollziehen (to execute) + -bar (able).\nMeans: possible to retrace or follow step by step.",example:"A: Ist das Argument nachvollziehbar?\nB: Ja, jeder Schritt ist nachvollziehbar.\nA: Manche Theorien sind kaum nachvollziehbar.\nB: Dann fehlt die Erklärung.",exampleSrc:"A: Is the argument comprehensible?\nB: Yes, every step is traceable.\nA: Some theories are hardly comprehensible.\nB: Then the explanation is missing.",funFact:"Nach (after) + vollziehen (to carry out) + -bar (able to be). You can literally retrace the steps. 'Nachvollziehbar' is the opposite of opaque or arbitrary. 'Das ist nicht nachvollziehbar' is a firm but polite objection in academic and professional German."},
{type:"fb",s:"Die Ergebnisse der Studie sind leicht {1}.",a:["nachvollziehbar"],opts:["nachvollziehbar","nachvollzogen","nachvollziehen","Nachvollziehung"],hint:"The -bar adjective meaning 'kann nachvollzogen werden'. A passive alternative: comprehensible, traceable.",sSrc:"The results of the study are easily comprehensible."},
{type:"drag_fill",s:"{1} Qualitaetszeitungen gründlich recherchieren, verbreitet die Boulevardpresse oft {2} Schlagzeilen.",blanks:{"1":"Während","2":"irreführende"},pool:["Während","irreführende","Weil","serioese","Obwohl","faktenbasierte"],hint:"Contrast: quality papers research, while tabloid press spreads misleading headlines. Adversative connector + Partizipialattribut."},
{type:"mc",q:"Welche drei Faehigkeiten gehören zur Medienkompetenz?",opts:["Schnell überfliegen + vorlesen + Schlagzeilen regelmä\u00dfig auswendig lernen","Nur eine einzige Zeitung lesen + der Regierung vertrauen + alle Kommentare konsequent ignorieren","Quellen überprüfen + Partizipialattribute verstehen + Fakten von Meinungen unterscheiden","Soziale Medien konsequent meiden + ausschließlich fernsehen + keine Fragen stellen"],ans:"Quellen überprüfen + Partizipialattribute verstehen + Fakten von Meinungen unterscheiden",hint:"Media literacy means: checking sources, understanding complex language structures, and separating facts from opinions."},
{type:"match",pairs:[{trg:"Partizipialattribut",src:"participle before a noun"},{trg:"Passiversatz",src:"passive alternative"},{trg:"Adversativsatz",src:"contrast clause"},{trg:"Medienkompetenz",src:"media literacy"}]},

{type:"mc",q:"Die Zeitung hat eine Auflage von 500.000 Exemplaren. Was ist 'die Auflage'?",opts:["the headline","the circulation, print run","the subscription","the article"],ans:"the circulation, print run",hint:"The total number of copies of a newspaper or magazine that are produced and distributed. 'Auf' (on) + 'lage' (layer/edition)."},

{type:"fb",s:"Die {1} macht es schwer, seriöse Nachrichten zu finden.",a:["Informationsflut"],opts:["Informationsflut","Verleumdung","Medienkompetenz","Auflage"],hint:"An overwhelming flood of data and news that makes it hard to find what matters.",sSrc:"The information overload makes it hard to find serious news."},

{type:"mc",q:"Er klagt wegen Verleumdung vor Gericht. Was ist 'die Verleumdung'?",opts:["the investigation","the publication","the slander, defamation","the circulation"],ans:"the slander, defamation",hint:"Spreading false and damaging statements about someone. A legal offense."}
]}
]};

export default UNIT_26;
